			["MbKitCreated"] = "Kit de diagnosticare creat:\n\n{0}",
			["MbWipeTitle"] = "DriveForge — ștergere sigură",
			["Mb030"] = "Spațiu liber insuficient pentru testare. Golește sau formatează mai întâi discul.",
			["MbWipeConfirm"] = "ȘTERGI ÎN SIGURANȚĂ (golești) acest disc?\n\n    Discul {0} — {1} — {2}\n\nAcest disc conține în prezent:\n{3}\n\n⚠ Fiecare sector va fi SUPRASCRIS. Datele NU vor mai putea fi recuperate. Această acțiune nu poate fi anulată.",
			["MbShredConfirm"] = "Distrugi definitiv {0} fișier(e)?\n\nConținutul fiecărui fișier va fi suprascris ({1} trecere(i)) și apoi șters. Această acțiune nu poate fi anulată.\n\n(Notă: pe SSD-uri/memorii flash USB, nivelarea uzurii înseamnă că pot rămâne fizic câteva copii; pentru certitudine absolută pe flash, fă și o Ștergere completă a discului sau folosește funcția Secure Erase a discului.)",
			["MbSchedWeekly"] = "în fiecare duminică",
			["Mb037"] = "Introdu unitatea USB pe care vrei să o folosești, apoi încearcă din nou.",
			["Mb040"] = "Repornește DriveForge ca administrator pentru a rula un test de suprafață.",
			["Mb034"] = "Nu s-a putut găsi automat un link de descărcare actual. Folosește în schimb butonul de pe pagina oficială de descărcare.",
			["MbFormatDone"] = "Gata. Discul {0} a fost formatat ca {1} și este gata de utilizare.",
			["Mb031"] = "Acesta este un disc de sistem — DriveForge nu îl va testa la pornire.",
			["MbBootHelp"] = "\n\nCum pornești de pe el: conectează discul la PC-ul țintă, pornește-l și deschide meniul de pornire (de obicei F12, F9, Esc sau F2 imediat după pornire), apoi alege acest USB/SSD. Prima pornire durează câteva minute cât timp Windows configurează driverele.",
			["MbBitLockerNote"] = "\n\nNotă: BitLocker încă criptează în fundal — păstrează discul conectat până ajunge la 100% (manage-bde -status), altfel se va finaliza la prima pornire a clonei.",
			["MbReinstallConfirm"] = "Reinstalarea va ȘTERGE toate fișierele (inclusiv imaginile tale ISO) de pe discul {0}. Continui?",
			["Mb028"] = "DriveForge nu va rula testul de capacitate pe un disc de sistem.",
