			["Mb045"] = "Repornește DriveForge ca administrator pentru a gestiona partiții.",
			["Mb022"] = "Repornește DriveForge ca administrator pentru a șterge discuri.",
			["MbMultiBootDone"] = "Gata! Discul {0} este acum un USB multi-boot.\n\nCopiază fișierele tale ISO pe unitatea \"Ventoy\" care tocmai s-a deschis — adaugă câte încap (Windows, Linux, instrumente de salvare).\n\nPornește orice PC de pe acest disc și alege o imagine ISO din meniu. Sfat: folosește Test de pornire pentru a verifica dacă pornește.",
			["Mb021"] = "Acesta este un disc de sistem — DriveForge nu îl va șterge.",
			["MbIsoTooBig"] = "Imaginea ISO ({0}) este mai mare decât discul ({1}).",
			["Mb018"] = "Acesta este un disc de sistem — nu poate fi scos.",
			["Mb015"] = "Încă nu este disponibil niciun raport.",
			["Mb016"] = "Acest disc nu are literă de unitate. Formatează-l mai întâi, apoi șterge spațiul liber.",
			["Mb013"] = "Parolele nu se potrivesc.",
			["MbNoFreeWipe"] = "Nu există aproape deloc spațiu liber de șters pe {0}:.",
			["MbSchedCreated"] = "Activitatea programată \"DriveForge Auto Clone\" a fost creată.\n\nVa clona acest PC pe „{0}” {1} la ora 02:00, atât timp cât acel disc este conectat.\n\nO poți elimina oricând din Windows Task Scheduler (sau este înlocuită dacă programezi din nou).",
			["MbWipeFreeConfirm"] = "Ștergi spațiul liber de pe {0}:?\n\nFișierele tale existente NU sunt atinse. DriveForge umple cei {1} de spațiu liber cu date de suprascriere ({2} trecere(i)) și apoi le elimină, astfel încât fișierele șterse anterior să nu mai poată fi recuperate.\n\nDiscul va fi temporar plin în timpul procesului. Continui?",
			["Mb038"] = "Multi-boot este alimentat de motorul gratuit, open-source Ventoy (GPL-3.0). DriveForge trebuie să îl descarce o singură dată (~16 MB); este apoi stocat în cache pentru utilizare offline.\n\nÎl descarci acum?",
			["Mb035"] = "Lipește un link http(s) direct către un fișier ISO.",
			["Mb032"] = "Repornește DriveForge ca administrator pentru a rula testul de pornire.",
			["Mb020"] = "Selectează mai întâi discul de șters (Disc de testat).",
			["MbBootTestOfflineWarn"] = "Testul de pornire s-a finalizat, dar readucerea discului {0} online ar fi putut eșua.\n\nDacă discul lipsește din Explorer, reactivează-l în Disk Management sau rulează într-un PowerShell de administrator:\n    Set-Disk -Number {0} -IsOffline $false",
			["MbWriteIsoConfirm"] = "Scrii această imagine ISO pe USB ca imagine bootabilă?\n\n    ISO: {0} ({1})\n    Către: discul {2} — {3} — {4}\n\nAcest disc conține în prezent:\n{5}\n\n⚠ Tot ce este pe disc va fi ȘTERS. (Funcționează pentru imagini ISO Linux și alte imagini isohybrid; o imagine ISO de Windows este mai bine creată cu \"Create Windows USB\".)",
			["Mb041"] = "Nimic selectat.",
			["MbHyperV"] = "Testul de pornire necesită funcția Hyper-V, care nu este activată pe acest PC.\n\nDeschizi \"Turn Windows features on or off\" ca să poți activa Hyper-V? (După activare este necesară o repornire.)",
			["Mb044"] = "Repornește DriveForge ca administrator pentru a formata discuri.",
			["MbBootTestConfirm"] = "Testezi pornirea acestui disc într-o mașină virtuală?\n\n    Discul {0} — {1} — {2}\n\nDriveForge va:\n• scoate acest disc offline (ca VM-ul să îl poată folosi),\n• porni un VM {3} temporar care pornește de pe el,\n• deschide o fereastră ca să poți urmări pornirea.\n\nDoar urmărește să ajungă la meniul/sigla de pornire — NU rula un program de instalare în interiorul VM-ului. Când ai terminat, revino aici și apasă OK pentru a opri testul și a readuce discul online.",
			["Mb019"] = "Discul a fost golit și scos în siguranță.\n\nDacă Windows încă îl afișează, așteaptă un moment, apoi deconectează-l. (Discurile interne SATA/NVMe s-ar putea să nu poată fi scoase — este normal.)",
			["MbSurfaceConfirm"] = "Rulezi un test de suprafață doar pentru citire pe:\n    Discul {0} — {1} — {2}\n\nDriveForge citește fiecare sector pentru a găsi blocuri defecte/necitibile. Nu se scrie nimic. Discurile mari pot dura ceva timp — folosește Stop pentru a anula.",
			["MbVmRunning"] = "VM-ul de test de pornire rulează și fereastra lui s-a deschis.\n\n• Dacă vezi sigla/meniul de pornire al discului, pornește corect. ✓\n• Un ecran negru sau \"no bootable device\" înseamnă că nu pornește — încearcă celălalt mod de firmware (UEFI ↔ Legacy BIOS).\n\nApasă OK când ai terminat pentru a opri testul și a readuce discul online.",
			["MbMultiBootTitle"] = "DriveForge — USB multi-boot",
