			["MbSchedCreated"] = "Tarea programada \"DriveForge Auto Clone\" creada.\n\nClonará este PC en '{0}' {1} a las 02:00, siempre que esa unidad esté conectada.\n\nQuítela cuando quiera desde el Task Scheduler de Windows (o se reemplaza si la programa de nuevo).",
			["MbWipeFreeConfirm"] = "¿Borrar el espacio libre en {0}:?\n\nSus archivos existentes NO se tocan. DriveForge llena los {1} de espacio libre con datos de sobrescritura ({2} pasada(s)) y luego los elimina, de modo que los archivos que borró antes ya no se pueden recuperar.\n\nLa unidad estará temporalmente llena durante el proceso. ¿Continuar?",
			["Mb038"] = "El multiarranque funciona con el motor gratuito y de código abierto Ventoy (GPL-3.0). DriveForge necesita descargarlo una vez (~16 MB); después queda en caché para usarlo sin conexión.\n\n¿Descargarlo ahora?",
			["Mb035"] = "Pegue un enlace http(s) directo a un archivo ISO.",
			["Mb032"] = "Reinicie DriveForge como administrador para ejecutar la prueba de arranque.",
			["Mb020"] = "Seleccione primero la unidad que desea borrar (Unidad a probar).",
			["MbBootTestOfflineWarn"] = "La prueba de arranque finalizó, pero es posible que volver a poner en línea el Disco {0} haya fallado.\n\nSi la unidad no aparece en Explorer, vuelva a habilitarla en Disk Management o ejecute en una PowerShell de administrador:\n    Set-Disk -Number {0} -IsOffline $false",
			["MbWriteIsoConfirm"] = "¿Escribir este ISO en el USB como imagen arrancable?\n\n    ISO: {0} ({1})\n    En: Disco {2} — {3} — {4}\n\nEste disco contiene actualmente:\n{5}\n\n⚠ Todo lo que hay en el disco se BORRARÁ. (Funciona con Linux y otros ISO isohybrid; un ISO de Windows se crea mejor con \"Create Windows USB\".)",
			["Mb041"] = "Nada seleccionado.",
			["MbHyperV"] = "La prueba de arranque necesita la característica Hyper-V, que no está habilitada en este PC.\n\n¿Abrir \"Turn Windows features on or off\" para habilitar Hyper-V? (Es necesario reiniciar después de habilitarla.)",
			["Mb044"] = "Reinicie DriveForge como administrador para formatear unidades.",
			["MbBootTestConfirm"] = "¿Probar el arranque de esta unidad en una máquina virtual?\n\n    Disco {0} — {1} — {2}\n\nDriveForge hará lo siguiente:\n• poner este disco sin conexión (para que la VM pueda usarlo),\n• iniciar una VM temporal {3} que arranque desde él,\n• abrir una ventana para que pueda ver cómo arranca.\n\nSolo observe que llega al menú de arranque / logotipo; NO ejecute un instalador dentro de la VM. Cuando termine, vuelva aquí y haga clic en OK para detener la prueba y volver a poner el disco en línea.",
			["Mb019"] = "La unidad se ha vaciado y expulsado.\n\nSi Windows aún la muestra, espere un momento y desconéctela. (Los discos internos SATA/NVMe pueden no expulsarse, eso es normal.)",
			["MbSurfaceConfirm"] = "Ejecutar una prueba de superficie de solo lectura en:\n    Disco {0} — {1} — {2}\n\nDriveForge lee cada sector para encontrar bloques defectuosos/ilegibles. No se escribe nada. Las unidades grandes pueden tardar un rato; use Stop para cancelar.",
			["MbVmRunning"] = "La VM de prueba de arranque se está ejecutando y su ventana se ha abierto.\n\n• Si ve el logotipo / menú de arranque de la unidad, arranca correctamente. ✓\n• Una pantalla negra o \"no bootable device\" significa que no arranca; pruebe el otro modo de firmware (UEFI ↔ Legacy BIOS).\n\nHaga clic en OK cuando termine para detener la prueba y volver a poner el disco en línea.",
			["MbMultiBootTitle"] = "DriveForge — USB multiarranque",
			["Mb017"] = "Seleccione primero la unidad que desea quitar (paso 3).",
			["MbShredTitle"] = "DriveForge — triturado seguro",
			["MbCapacityTitle"] = "DriveForge — prueba de capacidad",
			["MbCapacityConfirm"] = "Verificar la capacidad REAL de:\n    {0} ({1}:) — declara {2}\n\nEsto escribe ~{3} de datos de prueba en el espacio LIBRE, los vuelve a leer para verificarlos y luego los elimina. Sus archivos existentes NO se tocan. Para una comprobación completa, ejecútelo en una unidad vacía.\n\n¿Continuar?",
			["MbDownloaded"] = "Descargado:\n    {0}\n\n¿Abrir la carpeta ahora?",
			["Mb001"] = "Seleccione primero la unidad de destino (paso 3).",
			["Mb002"] = "No se pudo determinar la ruta de la aplicación para programarla.",
			["BzBootVm"] = "Iniciando la VM de prueba de arranque para el Disco {0}...",
			["MbUsbDone"] = "Creación del USB finalizada.",
			["Mb007"] = "Seleccione primero un USB/SSD de destino.",
			["BzWiping"] = "Borrando el Disco {0} ({1})...",
			["MbSurfaceTitle"] = "DriveForge — prueba de superficie",
			["Mb008"] = "El disco seleccionado está marcado como disco de sistema/arranque. DriveForge no lo formateará.",
			["Mb026"] = "¿Verificar ahora la imagen escrita?\n\nDriveForge leerá los datos de la unidad y los comparará byte a byte con el ISO para confirmar que se escribió correctamente (recomendado).",
			["BzCapacity"] = "Probando la capacidad real de {0}:...",
			["Mb025"] = "Esto parece un ISO de Windows / WinPE.\n\nLos ISO de Windows no son \"isohybrid\", por lo que escribir uno como imagen sin procesar normalmente NO arranca. Para un USB de Windows arrancable correcto, use mejor la tarea \"Create Windows USB\".\n\n¿Escribirlo igualmente sin procesar?",
			["Mb003"] = "Seleccione primero un ISO / WIM / ESD de Windows (paso 2).",
			["BzVerify"] = "Verificando el Disco {0}...",
			["MbTestBootTitle"] = "DriveForge — prueba de arranque",
			["MbBackupCreated"] = "Imagen de copia de seguridad creada:\n\n{0}  ({1})\n\nPara restaurarla más tarde: elija \"Advanced: restore full disk image\", seleccione este .wim y elija la unidad de destino.",
			["MbFormatConfirm"] = "¿Formatear (borrar) esta unidad?\n\n    Disco {0} — {1} — {2}\n\nEste disco contiene actualmente:\n{3}\n\n⚠ TODO lo anterior se BORRARÁ permanentemente.",
			["MbSchedDaily"] = "todos los días",
			["MbBackupNoSpace"] = "No hay suficiente espacio libre donde está guardando la imagen.\n\nEspacio estimado necesario: ~{0}\nLibre en el destino: {1}",
			["MbWriteIsoTitle"] = "DriveForge — escribir ISO",
			["Mb014"] = "Las contraseñas de BitLocker deben tener al menos 8 caracteres (o deje ambas vacías para usar solo la clave de recuperación).",
			["BzShred"] = "Triturando {0} archivo(s)...",
