ón", ["MvGptUnsupported"] = "Mover particiones solo está disponible en discos MBR. En GPT, reescribir la tabla es demasiado arriesgado sin verificar — usa Reducir / Ampliar, o haz una copia y recrea la partición.", ["MvNoParts"] = "No se encontraron particiones en el MBR de este disco.", ["MvPickPart"] = "¿Qué partición quieres mover?", ["MvDirPrompt"] = "¿Mover la partición hacia el inicio o el final del disco?", ["MvLeft"] = "Hacia el inicio del disco", ["MvRight"] = "Hacia el final del disco", ["MvAmountPrompt"] = "¿Cuántos MB se debe mover la partición?", ["MvOutOfRange"] = "Ese movimiento se saldría del borde del disco o antes del primer 1 MB. Elige una cantidad menor.", ["MvOverlap"] = "Ese movimiento se solaparía con otra partición. Elige una cantidad menor o la otra dirección.", ["MvConfirm"] = "¿Mover la partición #{0} ({1})?\n\n    Desde el desplazamiento {2}\n    Al desplazamiento {3}\n\n⚠ EXPERIMENTAL. Los datos de la partición se reubican físicamente y se reescribe la tabla de particiones.\n\n• Crea primero una imagen del disco (Recuperar → Crear imagen de disco) por si acaso.\n• NO apagues ni desconectes durante el movimiento — no se puede interrumpir de forma segura.\n\n¿Continuar?", ["MvWorking"] = "Moviendo la partición — NO apagues…", ["MvDone"] = "Listo. La partición #{0} fue movida. Si falta una letra de unidad, revisa Administración de discos.", ["MvFailed"] = "No se pudo mover la partición. La tabla de particiones quedó sin cambios.", ["PtResize"] = "Redimensionar una partición (ampliar / reducir)", ["PtCreate"] = "Crear una partición (en el espacio libre)", ["PtCreatePrompt"] = "¿Tamaño de la nueva partición en MB? (vacío = todo el espacio sin asignar)", ["PtCreateConfirm"] = "¿Crear una nueva partición en el Disco {0} usando su espacio sin asignar?\n\nLas particiones existentes no se tocan.", ["PtCreateDone"] = "Listo. Se creó una nueva partición en el Disco {0}.", ["PtCreateFailed"] = "No se pudo crear una partición — puede que no haya espacio sin asignar en el disco. Consulta los detalles abajo.", ["PtDelete"] = "Eliminar una partición (liberar su espacio)", ["PtDeleteConfirm"] = "¿Eliminar el volumen {0}: y convertirlo en espacio sin asignar?\n\n⚠ Todo lo de {0}: se borrará permanentemente. No se puede deshacer.", ["PtDeleteDone"] = "Listo. El volumen {0}: fue eliminado; su espacio ahora está sin asignar.", ["PtResizePrompt"] = "¿Redimensionar el volumen {0}: — ampliar o reducir?", ["PtGrow"] = "Ampliar (extender al espacio libre que le sigue)", ["PtShrink"] = "Reducir (liberar espacio al final)", ["PtShrinkPrompt"] = "¿Cuántos MB liberar de {0}: ? (máx ≈ {1} MB)", ["PtGrowPrompt"] = "¿Cuántos MB añadir a {0}: ? (vacío = todo el espacio libre justo después)", ["PtBadAmount"] = "Introduce un número entero de megabytes.", ["PtShrinkConfirm"] = "¿Reducir {0}: en {1} MB?\n\nEl espacio liberado queda sin asignar. Tus archivos se conservan.", ["PtGrowConfirm"] = "¿Ampliar {0}: al espacio sin asignar que le sigue?", ["PtResizeWorking"] = "Redimensionando {0}: …", ["PtResizeDone"] = "Listo. El volumen {0}: fue redimensionado.", ["PtResizeFailed"] = "diskpart no pudo redimensionar el volumen — consulta los detalles abajo (p. ej. no hay espacio libre justo después, o limitado por archivos inamovibles).", ["PtNoDisk"] = "Selecciona primero un disco (Unidad a probar).", ["PtSystemBlocked"] = "Es un disco del sistema — DriveForge no modifica sus particiones.", ["PtTitle"] = "Herramientas de partición", ["PtPrompt"] = "Elige una acción para el Disco {0}:", ["PtQuickPart"] = "Partición rápida (borrar y recrear)", ["PtInit"] = "Inicializar un disco vacío / RAW", ["PtConvert"] = "Convertir MBR ↔ GPT (borra el disco)", ["PtCheck"] = "Comprobar sistema de archivos (CHKDSK)", ["PtActive"] = "Marcar la primera partición como activa (arranque MBR)", ["PtFindLost"] = "Buscar particiones perdidas (análisis de solo lectura)", ["PtConfirmBody"] = "¿{0} en este disco?\n\n    Disco {1} — {2} — {3}\n\nActualmente contiene:\n{4}\