			["AmShredWhatPrompt"] = "Que voulez-vous effacer en toute sécurité ?",
			["AmShredMethodPrompt"] = "Effacer en toute sécurité {0} fichier(s) ? Cette action est IRRÉVERSIBLE.",
			["DlgBitLockerPwd"] = "Mot de passe BitLocker",
			["AmMbOpen"] = "L'ouvrir — ajouter ou supprimer des fichiers ISO",
			["MbSchedTitle"] = "Planifier le clonage",
			["MbDownloadTitle"] = "DriveForge — télécharger un ISO",
			["MbKitCreated"] = "Kit de diagnostic créé :\n\n{0}",
			["MbWipeTitle"] = "DriveForge — effacement sécurisé",
			["Mb030"] = "Espace libre insuffisant pour effectuer le test. Videz ou formatez d'abord le lecteur.",
			["MbWipeConfirm"] = "EFFACER DE MANIÈRE SÉCURISÉE ce lecteur ?\n\n    Disque {0} — {1} — {2}\n\nCe disque contient actuellement :\n{3}\n\n⚠ Chaque secteur sera ÉCRASÉ. Les données ne pourront PAS être récupérées. Cette action est irréversible.",
			["MbShredConfirm"] = "Broyer définitivement {0} fichier(s) ?\n\nLe contenu de chaque fichier sera écrasé ({1} passe(s)) puis supprimé. Cette action est irréversible.\n\n(Remarque : sur les SSD/clés USB flash, le nivellement d'usure signifie que quelques copies peuvent subsister physiquement ; pour une certitude absolue sur la mémoire flash, effectuez aussi un effacement complet du lecteur ou utilisez la fonction Secure Erase du lecteur.)",
			["MbSchedWeekly"] = "tous les dimanches",
			["Mb037"] = "Insérez la clé USB que vous souhaitez utiliser, puis réessayez.",
			["Mb040"] = "Redémarrez DriveForge en tant qu'administrateur pour exécuter un test de surface.",
			["Mb034"] = "Impossible de trouver automatiquement un lien de téléchargement actuel. Utilisez plutôt le bouton de la page de téléchargement officielle.",
			["MbFormatDone"] = "Terminé. Le disque {0} a été formaté en {1} et est prêt à l'emploi.",
			["Mb031"] = "Il s'agit d'un disque système — DriveForge n'effectuera pas de test de démarrage dessus.",
			["MbBootHelp"] = "\n\nComment démarrer dessus : branchez le lecteur sur le PC cible, allumez-le et ouvrez le menu de démarrage (généralement F12, F9, Échap ou F2 juste après la mise sous tension), puis choisissez cette clé USB/ce SSD. Le premier démarrage prend quelques minutes pendant que Windows configure les pilotes.",
			["MbBitLockerNote"] = "\n\nRemarque : BitLocker chiffre toujours en arrière-plan — gardez le lecteur connecté jusqu'à ce qu'il atteigne 100 % (manage-bde -status), sinon il terminera au premier démarrage du clone.",
			["MbReinstallConfirm"] = "La réinstallation EFFACERA tous les fichiers (y compris vos ISO) sur le disque {0}. Continuer ?",
			["Mb028"] = "DriveForge n'exécutera pas le test de capacité sur un disque système.",
			["Mb042"] = "Sélectionnez d'abord le lecteur à formater (Lecteur à tester).",
			["Mb027"] = "Sélectionnez d'abord le lecteur à tester (Lecteur à tester).",
			["Mb045"] = "Redémarrez DriveForge en tant qu'administrateur pour gérer les partitions.",
			["Mb022"] = "Redémarrez DriveForge en tant qu'administrateur pour effacer des lecteurs.",
			["MbMultiBootDone"] = "Terminé ! Le disque {0} est désormais une clé USB multiboot.\n\nCopiez vos fichiers ISO sur le lecteur « Ventoy » qui vient de s'ouvrir — ajoutez-en autant que possible (Windows, Linux, outils de dépannage).\n\nDémarrez n'importe quel PC sur ce lecteur et choisissez un ISO dans le menu. Astuce : utilisez Test de démarrage pour vérifier qu'il démarre.",
			["Mb021"] = "Il s'agit d'un disque système — DriveForge ne l'effacera pas.",
			["MbIsoTooBig"] = "L'ISO ({0}) est plus grand que le lecteur ({1}).",
			["Mb018"] = "Il s'agit d'un disque système — il ne peut pas être éjecté.",
			["Mb015"] = "Aucun rapport n'est encore disponible.",
			["Mb016"] = "Ce lecteur n'a pas de lettre de lecteur. Formatez-le d'abord, puis effacez son espace libre.",
			["Mb013"] = "Les mots de passe ne correspondent pas.",
			["MbNoFreeWipe"] = "Il n'y a presque pas d'espace libre à effacer sur {0} :.",
			["MbSchedCreated"] = "La tâche planifiée « DriveForge Auto Clone » a été créée.\n\nElle clonera ce PC vers « {0} » {1} à 02h00, tant que ce lecteur est connecté.\n\nSupprimez-la à tout moment depuis le Task Scheduler de Windows (ou elle est remplacée si vous la planifiez à nouveau).",
			["MbWipeFreeConfirm"] = "Effacer l'espace libre sur {0} : ?\n\nVos fichiers existants ne sont PAS touchés. DriveForge remplit les {1} d'espace libre avec des données d'écrasement ({2} passe(s)), puis les supprime, afin que les fichiers que vous avez supprimés auparavant ne puissent plus être récupérés.\n\nLe lecteur sera temporairement plein pendant le processus. Continuer ?",
			["Mb038"] = "Le multiboot est assuré par le moteur Ventoy gratuit et open source (GPL-3.0). DriveForge doit le télécharger une fois (~16 Mo) ; il est ensuite mis en cache pour une utilisation hors ligne.\n\nLe télécharger maintenant ?",
			["Mb035"] = "Collez un lien http(s) direct vers un fichier ISO.",
			["Mb032"] = "Redémarrez DriveForge en tant qu'administrateur pour exécuter le test de démarrage.",
			["Mb020"] = "Sélectionnez d'abord le lecteur à effacer (Lecteur à tester).",
			["MbBootTestOfflineWarn"] = "Le test de démarrage est terminé, mais la remise en ligne du disque {0} a peut-être échoué.\n\nSi le lecteur est absent de l'Explorer, réactivez-le dans le Disk Management, ou exécutez dans un PowerShell administrateur :\n    Set-Disk -Number {0} -IsOffline $false",
			["MbWriteIsoConfirm"] = "Écrire cet ISO sur la clé USB en tant qu'image amorçable ?\n\n    ISO : {0} ({1})\n    Vers : disque {2} — {3} — {4}\n\nCe disque contient actuellement :\n{5}\n\n⚠ Tout le contenu du disque sera EFFACÉ. (Fonctionne pour Linux et les autres ISO isohybrides ; un ISO Windows est mieux créé avec \"Create Windows USB\".)",
			["Mb041"] = "Aucune sélection.",
			["MbHyperV"] = "Le test de démarrage nécessite la fonctionnalité Hyper-V, qui n'est pas activée sur ce PC.\n\nOuvrir « Turn Windows features on or off » pour activer Hyper-V ? (Un redémarrage est requis après l'activation.)",
			["Mb044"] = "Redémarrez DriveForge en tant qu'administrateur pour formater des lecteurs.",
			["MbBootTestConfirm"] = "Tester le démarrage de ce lecteur dans une machine virtuelle ?\n\n    Disque {0} — {1} — {2}\n\nDriveForge va :\n• mettre ce disque hors ligne (pour que la VM puisse l'utiliser),\n• démarrer une VM {3} temporaire qui démarre dessus,\n• ouvrir une fenêtre pour que vous puissiez le voir démarrer.\n\nVérifiez simplement qu'il atteint le menu / logo de démarrage — n'exécutez PAS de programme d'installation dans la VM. Une fois terminé, revenez ici et cliquez sur OK pour arrêter le test et remettre le disque en ligne.",
			["Mb019"] = "Le lecteur a été vidé et éjecté.\n\nSi Windows l'affiche encore, patientez un instant, puis débranchez-le. (Les disques SATA/NVMe internes peuvent ne pas s'éjecter — c'est normal.)",
			["MbSurfaceConfirm"] = "Exécuter un test de surface en lecture seule sur :\n    Disque {0} — {1} — {2}\n\nDriveForge lit chaque secteur pour détecter les blocs défectueux/illisibles. Rien n'est écrit. Les grands lecteurs peuvent prendre du temps — utilisez Stop pour annuler.",
			["MbVmRunning"] = "La VM de test de démarrage est en cours d'exécution et sa fenêtre s'est ouverte.\n\n• Si vous voyez le logo / menu de démarrage du lecteur, il démarre correctement. ✓\n• Un écran noir ou « no bootable device » signifie qu'il ne démarre pas — essayez l'autre mode de firmware (UEFI ↔ Legacy BIOS).\n\nCliquez sur OK lorsque vous avez terminé pour arrêter le test et remettre le disque en ligne.",
			["MbMultiBootTitle"] = "DriveForge — clé USB multiboot",
			["Mb017"] = "Sélectionnez d'abord le lecteur à retirer (étape 3).",
			["MbShredTitle"] = "DriveForge — broyage sécurisé",
			["MbCapacityTitle"] = "DriveForge — test de capacité",
			["MbCapacityConfirm"] = "Vérifier la capacité RÉELLE de :\n    {0} ({1} :) — annonce {2}\n\nCela écrit ~{3} de données de test dans l'espace LIBRE, les relit pour vérifier, puis les supprime. Vos fichiers existants ne sont PAS touchés. Pour une vérification complète, exécutez-le sur un lecteur vide.\n\nContinuer ?",
			["MbDownloaded"] = "Téléchargé :\n    {0}\n\nOuvrir le dossier maintenant ?",
			["Mb001"] = "Sélectionnez d'abord le lecteur cible (étape 3).",
			["Mb002"] = "Impossible de déterminer le chemin de l'application à planifier.",
			["BzBootVm"] = "Démarrage de la VM de test de démarrage pour le disque {0}...",
			["MbUsbDone"] = "Création de la clé USB terminée.",
			["Mb007"] = "Sélectionnez d'abord une clé USB/un SSD cible.",
			["BzWiping"] = "Effacement du disque {0} ({1})...",
			["MbSurfaceTitle"] = "DriveForge — test de surface",
			["Mb008"] = "Le disque sélectionné est marqué comme disque système/de démarrage. DriveForge ne le formatera pas.",
			["Mb026"] = "Vérifier l'image écrite maintenant ?\n\nDriveForge relira les données depuis le lecteur et les comparera octet par octet avec l'ISO pour confirmer que l'écriture s'est bien déroulée (recommandé).",
			["BzCapacity"] = "Test de la capacité réelle de {0} :...",
			["Mb025"] = "Cela ressemble à un ISO Windows / WinPE.\n\nLes ISO Windows ne sont pas « isohybrides », donc écrire l'un d'eux en image brute ne permet généralement PAS de démarrer. Pour une clé USB Windows amorçable correcte, utilisez plutôt la tâche \"Create Windows USB\".\n\nL'écrire quand même en brut ?",
			["Mb003"] = "Sélectionnez d'abord un ISO / WIM / ESD Windows (étape 2).",
			["BzVerify"] = "Vérification du disque {0}...",
			["MbTestBootTitle"] = "DriveForge — test de démarrage",
			["MbBackupCreated"] = "Image de sauvegarde créée :\n\n{0}  ({1})\n\nPour la restaurer ultérieurement : choisissez « Avancé : restaurer une image disque complète », sélectionnez ce .wim, puis choisissez le lecteur cible.",
			["MbFormatConfirm"] = "Formater (effacer) ce lecteur ?\n\n    Disque {0} — {1} — {2}\n\nCe disque contient actuellement :\n{3}\n\n⚠ TOUT ce qui précède sera définitivement EFFACÉ.",
			["MbSchedDaily"] = "tous les jours",
			["MbBackupNoSpace"] = "Espace libre insuffisant à l'emplacement où vous enregistrez l'image.\n\nEspace estimé nécessaire : ~{0}\nLibre sur la destination : {1}",
			["MbWriteIsoTitle"] = "DriveForge — écrire un ISO",
