			["Mb006"] = "Arrêter l'opération en cours ? La clé USB risque d'être inachevée et de devoir être reformatée.",
			["Mb033"] = "Choisissez d'abord une distribution dans la liste.",
			["MbFormatTitle"] = "DriveForge — formater le lecteur",
			["Mb004"] = "Une opération est toujours en cours. Fermer l'application peut laisser la clé USB inachevée. Voulez-vous vraiment fermer ?",
			["Mb009"] = "Sélectionnez d'abord une image source.",
