ers (CHKDSK)", ["PtActive"] = "Définir la première partition active (indicateur d'amorçage MBR)", ["PtFindLost"] = "Rechercher des partitions perdues (analyse en lecture seule)", ["PtConfirmBody"] = "{0} sur ce disque ?\n\n    Disque {1} — {2} — {3}\n\nContient actuellement :\n{4}\n\n⚠ Tout sera EFFACÉ. Irréversible.", ["PtWorking"] = "{0} sur le disque sélectionné…", ["PtCountPrompt"] = "Combien de partitions créer sur le Disque {0} ?", ["PtFsPrompt"] = "Choisissez le système de fichiers des nouvelles partitions :", ["PtQuickDone"] = "Terminé. Le Disque {0} a maintenant {1} × {2} partition(s).", ["PtInitPrompt"] = "Initialiser le Disque {0} avec quel style de partition ?", ["PtGpt"] = "GPT (moderne, >2 To, UEFI)", ["PtMbr"] = "MBR (ancien, BIOS)", ["PtInitDone"] = "Terminé. Le Disque {0} a été initialisé et formaté (NTFS).", ["PtConvertConfirm"] = "Convertir le Disque {0} de {1} vers {2} ?\n\n⚠ Ceci EFFACE le disque. Irréversible.", ["PtConvertDone"] = "Terminé. Le Disque {0} est maintenant {1}.", ["PtNoVolumes"] = "Ce disque n'a aucun volume formaté à vérifier.", ["PtPickVolume"] = "Quel volume voulez-vous vérifier ?", ["PtChecking"] = "Vérification de {0} : …", ["PtCheckDone"] = "Vérification de {0} : terminée.", ["PtActiveGpt"] = "Sur un disque GPT il n'y a pas d'indicateur 'actif' — l'UEFI démarre depuis la partition système EFI.", ["PtActiveConfirm"] = "Définir la première partition du Disque {0} comme active (amorçable) ?", ["PtActiveDone"] = "Terminé. La première partition du Disque {0} est maintenant active.", ["PtScanningLost"] = "Analyse du Disque {0} à la recherche de partitions perdues…", ["PtLostNone"] = "Aucune signature de partition trouvée sur le Disque {0}.", ["PtLostUnmounted"] = "non montée (peut-être perdue)", ["PtLostMounted"] = "au début du disque", ["PtLostFound"] = "{0} partition(s) trouvée(s) sur le Disque {1} :", ["PtLostHint"] = "Analyse en lecture seule — rien n'a été modifié. Pour récupérer une partition perdue, utilisez un outil tiers 