			["MbShredConfirm"] = "{0} Datei(en) endgültig vernichten?\n\nDer Inhalt jeder Datei wird überschrieben ({1} Durchgang/Durchgänge) und dann gelöscht. Dies kann nicht rückgängig gemacht werden.\n\n(Hinweis: Bei SSDs/USB-Flash bedeutet Wear-Levelling, dass einige Kopien physisch verbleiben können; für absolute Sicherheit bei Flash führen Sie zusätzlich ein vollständiges Laufwerk-Löschen durch oder verwenden Sie das Secure Erase des Laufwerks.)",
			["MbSchedWeekly"] = "jeden Sonntag",
			["Mb037"] = "Stecken Sie den gewünschten USB-Stick ein und versuchen Sie es erneut.",
			["Mb040"] = "Starten Sie DriveForge als Administrator neu, um einen Oberflächentest auszuführen.",
			["Mb034"] = "Es konnte nicht automatisch ein aktueller Download-Link gefunden werden. Verwenden Sie stattdessen die Schaltfläche auf der offiziellen Download-Seite.",
			["MbFormatDone"] = "Fertig. Datenträger {0} wurde als {1} formatiert und ist einsatzbereit.",
			["Mb031"] = "Das ist ein Systemdatenträger – DriveForge führt keinen Boot-Test damit durch.",
			["MbBootHelp"] = "\n\nSo starten Sie davon: Stecken Sie das Laufwerk in den Ziel-PC, schalten Sie ihn ein und öffnen Sie das Boot-Menü (meist F12, F9, Esc oder F2 direkt nach dem Einschalten), und wählen Sie dann diesen USB/SSD. Der erste Start dauert einige Minuten, während Windows die Treiber einrichtet.",
			["MbBitLockerNote"] = "\n\nHinweis: BitLocker verschlüsselt weiterhin im Hintergrund – lassen Sie das Laufwerk angeschlossen, bis es 100 % erreicht (manage-bde -status), andernfalls wird die Verschlüsselung beim ersten Start des Klons abgeschlossen.",
			["MbReinstallConfirm"] = "Bei der Neuinstallation werden alle Dateien (einschließlich Ihrer ISOs) auf Datenträger {0} GELÖSCHT. Fortfahren?",
			["Mb028"] = "DriveForge führt den Kapazitätstest nicht auf einem Systemdatenträger aus.",
			["Mb042"] = "Wählen Sie zuerst das zu formatierende Laufwerk aus (Zu testendes Laufwerk).",
			["Mb027"] = "Wählen Sie zuerst das zu testende Laufwerk aus (Zu testendes Laufwerk).",
			["Mb045"] = "Starten Sie DriveForge als Administrator neu, um Partitionen zu verwalten.",
			["Mb022"] = "Starten Sie DriveForge als Administrator neu, um Laufwerke zu löschen.",
			["MbMultiBootDone"] = "Fertig! Datenträger {0} ist jetzt ein Multi-Boot-USB.\n\nKopieren Sie Ihre ISO-Dateien auf das soeben geöffnete \"Ventoy\"-Laufwerk – fügen Sie so viele hinzu, wie hineinpassen (Windows, Linux, Rettungstools).\n\nStarten Sie einen beliebigen PC von diesem Laufwerk und wählen Sie eine ISO aus dem Menü. Tipp: Verwenden Sie Boot-Test, um zu überprüfen, ob es bootet.",
			["Mb021"] = "Das ist ein Systemdatenträger – DriveForge löscht ihn nicht.",
			["MbIsoTooBig"] = "Die ISO ({0}) ist größer als das Laufwerk ({1}).",
			["Mb018"] = "Das ist ein Systemdatenträger – er kann nicht ausgeworfen werden.",
			["Mb015"] = "Es ist noch kein Bericht verfügbar.",
			["Mb016"] = "Dieses Laufwerk hat keinen Laufwerksbuchstaben. Formatieren Sie es zuerst und löschen Sie dann den freien Speicherplatz.",
			["Mb013"] = "Die Passwörter stimmen nicht überein.",
			["MbNoFreeWipe"] = "Auf {0}: ist fast kein freier Speicherplatz zum Löschen vorhanden.",
			["MbSchedCreated"] = "Geplante Aufgabe \"DriveForge Auto Clone\" erstellt.\n\nDieser PC wird {1} um 02:00 Uhr auf '{0}' geklont, sofern dieses Laufwerk angeschlossen ist.\n\nEntfernen Sie sie jederzeit über Task Scheduler von Windows (oder sie wird ersetzt, wenn Sie erneut eine Planung vornehmen).",
			["MbWipeFreeConfirm"] = "Freien Speicherplatz auf {0}: löschen?\n\nIhre vorhandenen Dateien werden NICHT angetastet. DriveForge füllt die {1} freien Speicherplatz mit Überschreibdaten ({2} Durchgang/Durchgänge) und entfernt sie anschließend, sodass zuvor gelöschte Dateien nicht mehr wiederhergestellt werden können.\n\nDas Laufwerk ist während des Vorgangs vorübergehend voll. Fortfahren?",
			["Mb038"] = "Multi-Boot wird von der kostenlosen Open-Source-Engine Ventoy (GPL-3.0) bereitgestellt. DriveForge muss sie einmalig herunterladen (~16 MB); danach wird sie für die Offline-Nutzung zwischengespeichert.\n\nJetzt herunterladen?",
			["Mb035"] = "Fügen Sie einen direkten http(s)-Link zu einer ISO-Datei ein.",
			["Mb032"] = "Starten Sie DriveForge als Administrator neu, um den Boot-Test auszuführen.",
			["Mb020"] = "Wählen Sie zuerst das zu löschende Laufwerk aus (Zu testendes Laufwerk).",
			["MbBootTestOfflineWarn"] = "Der Boot-Test wurde abgeschlossen, aber das Wiederonlineschalten von Datenträger {0} ist möglicherweise fehlgeschlagen.\n\nWenn das Laufwerk im Explorer fehlt, aktivieren Sie es in Disk Management erneut oder führen Sie in einer Admin-PowerShell aus:\n    Set-Disk -Number {0} -IsOffline $false",
			["MbWriteIsoConfirm"] = "Diese ISO als bootfähiges Abbild auf den USB-Stick schreiben?\n\n    ISO: {0} ({1})\n    Auf: Datenträger {2} — {3} — {4}\n\nDieser Datenträger enthält derzeit:\n{5}\n\n⚠ Alles auf dem Datenträger wird GELÖSCHT. (Funktioniert für Linux und andere isohybrid-ISOs; eine Windows-ISO wird besser mit \"Create Windows USB\" erstellt.)",
			["Mb041"] = "Nichts ausgewählt.",
			["MbHyperV"] = "Der Boot-Test benötigt die Hyper-V-Funktion, die auf diesem PC nicht aktiviert ist.\n\n\"Turn Windows features on or off\" öffnen, damit Sie Hyper-V aktivieren können? (Nach der Aktivierung ist ein Neustart erforderlich.)",
			["Mb044"] = "Starten Sie DriveForge als Administrator neu, um Laufwerke zu formatieren.",
			["MbBootTestConfirm"] = "Dieses Laufwerk in einer virtuellen Maschine per Boot-Test prüfen?\n\n    Datenträger {0} — {1} — {2}\n\nDriveForge wird:\n• diesen Datenträger offline schalten (damit die VM ihn nutzen kann),\n• eine temporäre {3}-VM starten, die davon bootet,\n• ein Fenster öffnen, damit Sie den Bootvorgang beobachten können.\n\nAchten Sie nur darauf, dass das Boot-Menü / Logo erreicht wird – führen Sie KEIN Installationsprogramm in der VM aus. Wenn Sie fertig sind, kehren Sie hierher zurück und klicken Sie auf OK, um den Test zu beenden und den Datenträger wieder online zu schalten.",
			["Mb019"] = "Das Laufwerk wurde geleert und ausgeworfen.\n\nFalls Windows es noch anzeigt, warten Sie einen Moment und ziehen Sie es dann ab. (Interne SATA-/NVMe-Datenträger lassen sich möglicherweise nicht auswerfen – das ist normal.)",
			["MbSurfaceConfirm"] = "Einen schreibgeschützten Oberflächentest ausführen auf:\n    Datenträger {0} — {1} — {2}\n\nDriveForge liest jeden Sektor, um fehlerhafte/unlesbare Blöcke zu finden. Es wird nichts geschrieben. Große Laufwerke können eine Weile dauern – verwenden Sie Stop zum Abbrechen.",
			["MbVmRunning"] = "Die Boot-Test-VM läuft und ihr Fenster wurde geöffnet.\n\n• Wenn Sie das Boot-Logo / -Menü des Laufwerks sehen, bootet es korrekt. ✓\n• Ein schwarzer Bildschirm oder \"no bootable device\" bedeutet, dass es nicht bootet – versuchen Sie den anderen Firmware-Modus (UEFI ↔ Legacy BIOS).\n\nKlicken Sie auf OK, wenn Sie fertig sind, um den Test zu beenden und den Datenträger wieder online zu schalten.",
			["MbMultiBootTitle"] = "DriveForge — Multi-Boot-USB",
			["Mb017"] = "Wählen Sie zuerst das zu entfernende Laufwerk aus (Schritt 3).",
			["MbShredTitle"] = "DriveForge — sichere Vernichtung",
			["MbCapacityTitle"] = "DriveForge — Kapazitätstest",
			["MbCapacityConfirm"] = "Die ECHTE Kapazität überprüfen von:\n    {0} ({1}:) — angegeben {2}\n\nDies schreibt ~{3} Testdaten in den FREIEN Speicherplatz, liest sie zur Überprüfung zurück und löscht sie dann. Ihre vorhandenen Dateien werden NICHT angetastet. Für eine vollständige Prüfung führen Sie ihn auf einem leeren Laufwerk aus.\n\nFortfahren?",
			["MbDownloaded"] = "Heruntergeladen:\n    {0}\n\nDen Ordner jetzt öffnen?",
			["Mb001"] = "Wählen Sie zuerst das Ziellaufwerk aus (Schritt 3).",
			["Mb002"] = "Der Anwendungspfad für die Planung konnte nicht ermittelt werden.",
			["BzBootVm"] = "Boot-Test-VM für Datenträger {0} wird gestartet...",
			["MbUsbDone"] = "USB-Erstellung abgeschlossen.",
			["Mb007"] = "Wählen Sie zuerst einen Ziel-USB/-SSD aus.",
			["BzWiping"] = "Datenträger {0} ({1}) wird gelöscht...",
			["MbSurfaceTitle"] = "DriveForge — Oberflächentest",
			["Mb008"] = "Der ausgewählte Datenträger ist als System-/Startdatenträger markiert. DriveForge formatiert ihn nicht.",
			["Mb026"] = "Das geschriebene Abbild jetzt überprüfen?\n\nDriveForge liest die Daten vom Laufwerk zurück und vergleicht sie Byte für Byte mit der ISO, um zu bestätigen, dass sie korrekt geschrieben wurde (empfohlen).",
			["BzCapacity"] = "Echte Kapazität von {0}: wird getestet...",
			["Mb025"] = "Dies sieht nach einer Windows- / WinPE-ISO aus.\n\nWindows-ISOs sind nicht \"isohybrid\", daher startet ein als Roh-Abbild geschriebenes Image in der Regel NICHT. Verwenden Sie für einen ordnungsgemäß bootfähigen Windows-USB-Stick stattdessen die Aufgabe \"Create Windows USB\".\n\nTrotzdem roh schreiben?",
			["Mb003"] = "Wählen Sie zuerst eine Windows-ISO / WIM / ESD aus (Schritt 2).",
			["BzVerify"] = "Datenträger {0} wird überprüft...",
			["MbTestBootTitle"] = "DriveForge — Boot-Test",
			["MbBackupCreated"] = "Sicherungsabbild erstellt:\n\n{0}  ({1})\n\nSo stellen Sie es später wieder her: Wählen Sie \"Erweitert: vollständiges Datenträgerabbild wiederherstellen\", wählen Sie diese .wim aus und wählen Sie das Ziellaufwerk.",
			["MbFormatConfirm"] = "Dieses Laufwerk formatieren (löschen)?\n\n    Datenträger {0} — {1} — {2}\n\nDieser Datenträger enthält derzeit:\n{3}\n\n⚠ ALLES oben Genannte wird dauerhaft GELÖSCHT.",
			["MbSchedDaily"] = "jeden Tag",
			["MbBackupNoSpace"] = "Nicht genügend freier Speicherplatz am Speicherort des Abbilds.\n\nGeschätzter Speicherbedarf: ~{0}\nFrei am Ziel: {1}",
			["MbWriteIsoTitle"] = "DriveForge — ISO schreiben",
			["Mb014"] = "BitLocker-Passwörter müssen mindestens 8 Zeichen lang sein (oder lassen Sie beide leer, um nur einen Wiederherstellungsschlüssel zu verwenden).",
			["BzShred"] = "{0} Datei(en) werden vernichtet...",
