			["MbFormatTitle"] = "DriveForge — Laufwerk formatieren",
			["Mb004"] = "Es läuft noch ein Vorgang. Wenn Sie die App schließen, bleibt der USB-Stick möglicherweise unvollständig. Möchten Sie wirklich schließen?",
			["Mb009"] = "Wählen Sie zuerst ein Quellabbild aus.",
			["MbWipeFreeTitle"] = "DriveForge — freien Speicherplatz löschen",
			["Mb010"] = "Starten Sie DriveForge als Administrator neu, bevor Sie den USB-Stick erstellen.",
			["MbHyperVTitle"] = "DriveForge — Hyper-V erforderlich",
			["BzWipeFree"] = "Freier Speicherplatz auf {0}: wird gelöscht...",
			["Mb043"] = "Das ist ein Systemdatenträger – DriveForge formatiert ihn nicht.",
			["BzFormat"] = "Datenträger {0} wird als {1} formatiert...",
			["Mb024"] = "Wählen Sie zuerst ein ISO-Abbild aus.",
			["BzWriteIso"] = "ISO-Abbild wird auf Datenträger {0} geschrieben...",
			["MbMultiBootSetup"] = "Datenträger {0} als Multi-Boot-USB einrichten?\n\n    {1} — {2}\n\nDieser Datenträger enthält derzeit:\n{3}\n\n⚠ Das Laufwerk wird GELÖSCHT und mit der Ventoy-Multi-Boot-Engine eingerichtet. Danach kopieren Sie einfach ISO-Dateien darauf (Windows, Linux, alles) und wählen beim Booten eine aus einem Menü aus.",
			["Mb023"] = "Jetzt ein Löschzertifikat erstellen?\n\nEs wird in Ihrem Browser geöffnet; verwenden Sie Drucken → \"Als PDF speichern\", um eine Kopie für Ihre Unterlagen zu behalten – praktisch beim Weiterverkauf eines Laufwerks oder als Nachweis für DSGVO / Datenentsorgung.",
			["MbCloneHelperCreated"] = "Hilfsdateien für den Klon des aktuellen Computers wurden erstellt:\n\n{0}\n\nEin vollständiger Klon kann nicht erfasst werden, während dieses Windows läuft. Starten Sie Windows PE, führen Sie das Erfassungsskript aus und wählen Sie dann in DriveForge 'Restore a full computer clone'.",
