den Datenträger zuerst.", ["MvTitle"] = "Partition verschieben", ["MvGptUnsupported"] = "Das Verschieben von Partitionen ist nur auf MBR-Datenträgern verfügbar. Auf GPT ist das Neuschreiben der Tabelle ungeprüft zu riskant — nutzen Sie Verkleinern / Vergrößern, oder sichern und erstellen Sie die Partition neu.", ["MvNoParts"] = "Im MBR dieses Datenträgers wurden keine Partitionen gefunden.", ["MvPickPart"] = "Welche Partition möchten Sie verschieben?", ["MvDirPrompt"] = "Partition zum Anfang oder zum Ende des Datenträgers verschieben?", ["MvLeft"] = "Zum Anfang des Datenträgers", ["MvRight"] = "Zum Ende des Datenträgers", ["MvAmountPrompt"] = "Um wie viele MB soll die Partition verschoben werden?", ["MvOutOfRange"] = "Diese Verschiebung würde über den Rand des Datenträgers oder vor das erste 1 MB hinausgehen. Wählen Sie einen kleineren Wert.", ["MvOverlap"] = "Diese Verschiebung würde eine andere Partition überlappen. Wählen Sie einen kleineren Wert oder die andere Richtung.", ["MvConfirm"] = "Partition #{0} ({1}) verschieben?\n\n    Von Offset {2}\n    Zu Offset {3}\n\n⚠ EXPERIMENTELL. Die Daten der Partition werden physisch verschoben und die Partitionstabelle neu geschrieben.\n\n• Erstellen Sie zuerst ein Abbild des Datenträgers (Wiederherstellen → Datenträgerabbild erstellen).\n• Schalten Sie während des Verschiebens NICHT aus und trennen Sie nicht — es kann nicht sicher unterbrochen werden.\n\nFortfahren?", ["MvWorking"] = "Partition wird verschoben — NICHT ausschalten…", ["MvDone"] = "Fertig. Partition #{0} wurde verschoben. Fehlt ein Laufwerkbuchstabe, prüfen Sie die Datenträgerverwaltung.", ["MvFailed"] = "Die Partition konnte nicht verschoben werden. Die Partitionstabelle blieb unverändert.", ["PtResize"] = "Partition vergrößern / verkleinern", ["PtCreate"] = "Partition erstellen (im freien Speicher)", ["PtCreatePrompt"] = "Größe der neuen Partition in MB? (leer = der gesamte nicht zugeordnete Speicher)", ["PtCreateConfirm"] = "Eine neue Partition auf Datenträger {0} im nicht zugeordneten Speicher erstellen?\n\nVorhandene Partitionen bleiben unberührt.", ["PtCreateDone"] = "Fertig. Auf Datenträger {0} wurde eine neue Partition erstellt.", ["PtCreateFailed"] = "Partition konnte nicht erstellt werden — möglicherweise kein nicht zugeordneter Speicher vorhanden. Siehe Details unten.", ["PtDelete"] = "Partition löschen (Speicher freigeben)", ["PtDeleteConfirm"] = "Volume {0}: löschen und in nicht zugeordneten Speicher umwandeln?\n\n⚠ Alles auf {0}: wird dauerhaft gelöscht. Nicht rückgängig zu machen.", ["PtDeleteDone"] = "Fertig. Volume {0}: wurde gelöscht; sein Speicher ist jetzt nicht zugeordnet.", ["PtResizePrompt"] = "Volume {0}: vergrößern oder verkleinern?", ["PtGrow"] = "Vergrößern (in den freien Speicher dahinter erweitern)", ["PtShrink"] = "Verkleinern (am Ende Speicher freigeben)", ["PtShrinkPrompt"] = "Wie viele MB von {0}: freigeben? (max ≈ {1} MB)", ["PtGrowPrompt"] = "Wie viele MB zu {0}: hinzufügen? (leer = der gesamte freie Speicher direkt dahinter)", ["PtBadAmount"] = "Geben Sie eine ganze Zahl an Megabyte ein.", ["PtShrinkConfirm"] = "{0}: um {1} MB verkleinern?\n\nDer freigegebene Speicher wird nicht zugeordnet. Ihre Dateien bleiben erhalten.", ["PtGrowConfirm"] = "{0}: in den nachfolgenden, nicht zugeordneten Speicher erweitern?", ["PtResizeWorking"] = "{0}: wird in der Größe geändert…", ["PtResizeDone"] = "Fertig. Volume {0}: wurde in der Größe geändert.", ["PtResizeFailed"] = "diskpart konnte das Volume nicht ändern — siehe Details unten (z. B. kein freier Speicher direkt dahinter oder durch nicht verschiebbare Dateien begrenzt).", ["PtNoDisk"] = "Wählen Sie zuerst einen Datenträger (Laufwerk zum Testen).", ["PtSystemBlocked"] = "Das ist ein Systemdatenträger — DriveForge ändert seine Partitionen nicht.", ["PtTitle"] = "Partitionswerkzeuge", ["PtPrompt"] = "Wählen Sie eine Aktion für Datenträger {0}:", ["PtQuickPart"] = "Schnellpartitionierung (löschen & neu erstellen)", ["PtInit"] = "Leeren / RAW-Dat