ion(en) auf Datenträger {1} gefunden:", ["PtLostHint"] = "Schreibgeschützter Scan – es wurde nichts verändert. Um eine verlorene Partition wiederherzustellen, verwende ein spezialisiertes Drittanbieter-Tool zur Partitionswiederherstellung; um ihre Dateien zu retten, erstelle ein Abbild der Festplatte und stelle aus dem Abbild wieder her.", ["WipeSsd"] = "SSD-Löschung (TRIM — die für SSDs passende Löschung)", ["SsdConfirm"] = "SSD-Löschung von Datenträger {0}?\n\n    {1} — {2}\n\nEnthält derzeit:\n{3}\n\n⚠ Alle Daten werden verworfen. Nicht rückgängig zu machen.", ["SsdWorking"] = "SSD-Löschung von Datenträger {0} (Formatieren + TRIM)…", ["SsdDone"] = "Fertig. Datenträger {0} wurde bereinigt und per TRIM gelöscht — bei einer SSD verwirft der Controller die alten Datenblöcke. Für zertifizierte Bereinigung nutzen Sie zusätzlich das Secure-Erase-Tool des Herstellers.", ["RecPreviewLabel"] = "Vorschau", ["EjectDriveButton"] = "Sicher entfernen", ["AddAllDriversCheck"] = "ALLE Treiber dieses PCs hinzufügen (langsamer)", ["AddNetworkDriversCheck"] = "Netzwerk-/WLAN-Treiber dieses PCs hinzufügen", ["EjectWhenDoneCheck"] = "Laufwerk nach Abschluss auswerfen", ["OpenReportButton"] = "Letzten Bericht öffnen", ["ScheduleCloneButton"] = "Diesen Klon planen (automatisches Backup)…", ["InternalDiskCheck"] = "Ziel ist eine interne Festplatte (normale Installation, nicht portabel)", ["StartBackup"] = "In Abbilddatei sichern", ["SbCleanT"] = "Spuren bereinigen", ["SbCleanS"] = "Speicher freigeben und Nutzungsspuren löschen", ["CleanPanelTitle"] = "Spuren bereinigen", ["CleanPanelDesc"] = "Geben Sie Speicherplatz frei und entfernen Sie die Nutzungsspuren, die Windows und Ihre Apps hinterlassen. Wählen Sie aus, was bereinigt werden soll, klicken Sie auf Analysieren, um zu sehen, wie viel frei wird, und dann auf Jetzt bereinigen. Nichts verlässt jemals Ihren PC.", ["ChkCleanTemp"] = "Temporäre Dateien (Windows + Apps)", ["ChkCleanRecent"] = "Zuletzt verwendete Dateien & Sprunglisten", [