			["MbKitCreated"] = "Kit de diagnóstico criado:\n\n{0}",
			["MbWipeTitle"] = "DriveForge — limpeza segura",
			["Mb030"] = "Não há espaço livre suficiente para testar. Esvazie ou formate primeiro a unidade.",
			["MbWipeConfirm"] = "LIMPAR EM SEGURANÇA (apagar) esta unidade?\n\n    Disco {0} — {1} — {2}\n\nEste disco contém atualmente:\n{3}\n\n⚠ Todos os setores serão SOBRESCRITOS. Os dados NÃO poderão ser recuperados. Isto não pode ser anulado.",
			["MbShredConfirm"] = "Destruir permanentemente {0} ficheiro(s)?\n\nO conteúdo de cada ficheiro será sobrescrito ({1} passagem(ns)) e depois apagado. Isto não pode ser anulado.\n\n(Nota: em SSDs/memória flash USB, o nivelamento de desgaste significa que algumas cópias podem permanecer fisicamente; para certeza absoluta em flash, faça também uma Limpeza completa da unidade ou use o Secure Erase da unidade.)",
			["MbSchedWeekly"] = "todos os domingos",
			["Mb037"] = "Insira a unidade USB que pretende usar e tente novamente.",
			["Mb040"] = "Reinicie o DriveForge como administrador para executar um teste de superfície.",
			["Mb034"] = "Não foi possível encontrar automaticamente um link de transferência atual. Use antes o botão da página de transferência oficial.",
			["MbFormatDone"] = "Concluído. O Disco {0} foi formatado como {1} e está pronto a usar.",
			["Mb031"] = "Este é um disco de sistema — o DriveForge não fará teste de arranque nele.",
			["MbBootHelp"] = "\n\nComo arrancar a partir dela: ligue a unidade ao PC de destino, ligue-o e abra o menu de arranque (normalmente F12, F9, Esc ou F2 logo após ligar), depois escolha este USB/SSD. O primeiro arranque demora alguns minutos enquanto o Windows configura os controladores.",
			["MbBitLockerNote"] = "\n\nNota: o BitLocker ainda está a encriptar em segundo plano — mantenha a unidade ligada até atingir 100% (manage-bde -status), ou terminará no primeiro arranque do clone.",
			["MbReinstallConfirm"] = "A reinstalação irá APAGAR todos os ficheiros (incluindo os seus ISOs) no Disco {0}. Continuar?",
			["Mb028"] = "O DriveForge não irá executar o teste de capacidade num disco de sistema.",
			["Mb042"] = "Selecione primeiro a unidade a formatar (Unidade a testar).",
			["Mb027"] = "Selecione primeiro a unidade a testar (Unidade a testar).",
			["Mb045"] = "Reinicie o DriveForge como administrador para gerir partições.",
			["Mb022"] = "Reinicie o DriveForge como administrador para limpar unidades.",
			["MbMultiBootDone"] = "Concluído! O Disco {0} é agora um USB multi-arranque.\n\nCopie os seus ficheiros ISO para a unidade \"Ventoy\" que acabou de abrir — adicione quantos couberem (Windows, Linux, ferramentas de recuperação).\n\nArranque qualquer PC a partir desta unidade e escolha um ISO no menu. Dica: use o teste de arranque para verificar se arranca.",
			["Mb021"] = "Este é um disco de sistema — o DriveForge não o irá limpar.",
			["MbIsoTooBig"] = "O ISO ({0}) é maior do que a unidade ({1}).",
			["Mb018"] = "Este é um disco de sistema — não pode ser ejetado.",
			["Mb015"] = "Ainda não há nenhum relatório disponível.",
			["Mb016"] = "Esta unidade não tem letra de unidade. Formate-a primeiro e depois limpe o seu espaço livre.",
			["Mb013"] = "As palavras-passe não coincidem.",
			["MbNoFreeWipe"] = "Quase não há espaço livre para limpar em {0}:.",
			["MbSchedCreated"] = "Tarefa agendada \"DriveForge Auto Clone\" criada.\n\nIrá clonar este PC para '{0}' {1} às 02:00, desde que essa unidade esteja ligada.\n\nRemova-a a qualquer momento a partir do Task Scheduler do Windows (ou será substituída se agendar novamente).",
			["MbWipeFreeConfirm"] = "Limpar o espaço livre em {0}:?\n\nOs seus ficheiros existentes NÃO são afetados. O DriveForge preenche os {1} de espaço livre com dados de sobrescrita ({2} passagem(ns)) e depois remove-os, para que os ficheiros que apagou antes já não possam ser recuperados.\n\nA unidade ficará temporariamente cheia durante o processo. Continuar?",
			["Mb038"] = "O multi-arranque é fornecido pelo motor Ventoy, gratuito e de código aberto (GPL-3.0). O DriveForge precisa de o transferir uma vez (~16 MB); fica depois em cache para uso offline.\n\nTransferir agora?",
			["Mb035"] = "Cole um link http(s) direto para um ficheiro ISO.",
			["Mb032"] = "Reinicie o DriveForge como administrador para executar o teste de arranque.",
			["Mb020"] = "Selecione primeiro a unidade a limpar (Unidade a testar).",
			["MbBootTestOfflineWarn"] = "O teste de arranque terminou, mas a colocação do Disco {0} novamente online pode ter falhado.\n\nSe a unidade estiver em falta no Explorer, reative-a no Disk Management, ou execute numa PowerShell de administrador:\n    Set-Disk -Number {0} -IsOffline $false",
			["MbWriteIsoConfirm"] = "Gravar este ISO no USB como uma imagem inicializável?\n\n    ISO: {0} ({1})\n    Para: Disco {2} — {3} — {4}\n\nEste disco contém atualmente:\n{5}\n\n⚠ Tudo no disco será APAGADO. (Funciona para Linux e outros ISOs isohybrid; um ISO do Windows é melhor criado com \"Create Windows USB\".)",
			["Mb041"] = "Nada selecionado.",
			["MbHyperV"] = "O teste de arranque precisa da funcionalidade Hyper-V, que não está ativada neste PC.\n\nAbrir \"Turn Windows features on or off\" para poder ativar o Hyper-V? (É necessário reiniciar após a ativação.)",
			["Mb044"] = "Reinicie o DriveForge como administrador para formatar unidades.",
			["MbBootTestConfirm"] = "Testar o arranque desta unidade numa máquina virtual?\n\n    Disco {0} — {1} — {2}\n\nO DriveForge irá:\n• colocar este disco offline (para que a VM o possa usar),\n• iniciar uma VM {3} temporária que arranca a partir dele,\n• abrir uma janela para poder observar o arranque.\n\nApenas verifique se chega ao menu / logótipo de arranque — NÃO execute um instalador dentro da VM. Quando terminar, volte aqui e clique em OK para parar o teste e colocar o disco novamente online.",
			["Mb019"] = "A unidade foi esvaziada e ejetada.\n\nSe o Windows ainda a mostrar, aguarde um momento e depois desligue-a. (Os discos internos SATA/NVMe podem não ejetar — isso é normal.)",
			["MbSurfaceConfirm"] = "Executar um teste de superfície só de leitura em:\n    Disco {0} — {1} — {2}\n\nO DriveForge lê todos os setores para encontrar blocos defeituosos/ilegíveis. Nada é gravado. As unidades grandes podem demorar — use Stop para cancelar.",
			["MbVmRunning"] = "A VM de teste de arranque está em execução e a sua janela foi aberta.\n\n• Se vir o logótipo / menu de arranque da unidade, ela arranca corretamente. ✓\n• Um ecrã preto ou \"no bootable device\" significa que não arranca — experimente o outro modo de firmware (UEFI ↔ Legacy BIOS).\n\nClique em OK quando terminar para parar o teste e colocar o disco novamente online.",
			["MbMultiBootTitle"] = "DriveForge — USB multi-arranque",
			["Mb017"] = "Selecione primeiro a unidade a remover (passo 3).",
			["MbShredTitle"] = "DriveForge — destruição segura",
			["MbCapacityTitle"] = "DriveForge — teste de capacidade",
			["MbCapacityConfirm"] = "Verificar a capacidade REAL de:\n    {0} ({1}:) — indica {2}\n\nIsto grava ~{3} de dados de teste no espaço LIVRE, lê-os de volta para verificar e depois apaga-os. Os seus ficheiros existentes NÃO são afetados. Para uma verificação completa, execute-o numa unidade vazia.\n\nContinuar?",
			["MbDownloaded"] = "Transferido:\n    {0}\n\nAbrir a pasta agora?",
			["Mb001"] = "Selecione primeiro a unidade de destino (passo 3).",
			["Mb002"] = "Não foi possível determinar o caminho da aplicação para agendar.",
