r partições só está disponível em discos MBR. No GPT, reescrever a tabela é arriscado demais sem verificação — use Reduzir / Aumentar, ou faça backup e recrie a partição.", ["MvNoParts"] = "Nenhuma partição encontrada no MBR deste disco.", ["MvPickPart"] = "Qual partição você quer mover?", ["MvDirPrompt"] = "Mover a partição para o início ou o final do disco?", ["MvLeft"] = "Para o início do disco", ["MvRight"] = "Para o final do disco", ["MvAmountPrompt"] = "Em quantos MB a partição deve ser movida?", ["MvOutOfRange"] = "Esse movimento passaria da borda do disco ou antes do primeiro 1 MB. Escolha um valor menor.", ["MvOverlap"] = "Esse movimento se sobreporia a outra partição. Escolha um valor menor ou a outra direção.", ["MvConfirm"] = "Mover a partição #{0} ({1})?\n\n    Do deslocamento {2}\n    Para o deslocamento {3}\n\n⚠ EXPERIMENTAL. Os dados da partição são realocados fisicamente e a tabela de partições é reescrita.\n\n• Crie primeiro uma imagem do disco (Recuperar → Criar imagem de disco) por precaução.\n• NÃO desligue nem desconecte durante o movimento — ele não pode ser interrompido com segurança.\n\nContinuar?", ["MvWorking"] = "Movendo a partição — NÃO desligue…", ["MvDone"] = "Concluído. A partição #{0} foi movida. Se faltar uma letra de unidade, verifique o Gerenciamento de Disco.", ["MvFailed"] = "Não foi possível mover a partição. A tabela de partições ficou inalterada.", ["PtResize"] = "Redimensionar uma partição (aumentar / reduzir)", ["PtCreate"] = "Criar uma partição (no espaço livre)", ["PtCreatePrompt"] = "Tamanho da nova partição em MB? (vazio = todo o espaço não alocado)", ["PtCreateConfirm"] = "Criar uma nova partição no Disco {0} usando o espaço não alocado?\n\nAs partições existentes não são tocadas.", ["PtCreateDone"] = "Concluído. Uma nova partição foi criada no Disco {0}.", ["PtCreateFailed"] = "Não foi possível criar uma partição — pode não haver espaço não alocado no disco. Veja os detalhes abaixo.", ["PtDelete"] = "Excluir uma partição (liberar o espaço)", ["PtDeleteConfirm"] = "Excluir o volume {0}: e transformá-lo em espaço não alocado?\n\n⚠ Tudo em {0}: será apagado permanentemente. Não pode ser desfeito.", ["PtDeleteDone"] = "Concluído. O volume {0}: foi excluído; o espaço dele agora está não alocado.", ["PtResizePrompt"] = "Redimensionar o volume {0}: — aumentar ou reduzir?", ["PtGrow"] = "Aumentar (estender para o espaço livre após ela)", ["PtShrink"] = "Reduzir (liberar espaço no final)", ["PtShrinkPrompt"] = "Quantos MB liberar de {0}: ? (máx ≈ {1} MB)", ["PtGrowPrompt"] = "Quantos MB adicionar a {0}: ? (vazio = todo o espaço livre logo após)", ["PtBadAmount"] = "Digite um número inteiro de megabytes.", ["PtShrinkConfirm"] = "Reduzir {0}: em {1} MB?\n\nO espaço liberado fica não alocado. Seus arquivos são mantidos.", ["PtGrowConfirm"] = "Aumentar {0}: para o espaço não alocado que vem a seguir?", ["PtResizeWorking"] = "Redimensionando {0}: …", ["PtResizeDone"] = "Concluído. O volume {0}: foi redimensionado.", ["PtResizeFailed"] = "O diskpart não conseguiu redimensionar o volume — veja os detalhes abaixo (ex. sem espaço livre logo após, ou limitado por arquivos que não podem ser movidos).", ["PtNoDisk"] = "Selecione primeiro um disco (Unidade a testar).", ["PtSystemBlocked"] = "É um disco do sistema — o DriveForge não modifica suas partições.", ["PtTitle"] = "Ferramentas de partição", ["PtPrompt"] = "Escolha uma ação para o Disco {0}:", ["PtQuickPart"] = "Partição rápida (apagar e recriar)", ["PtInit"] = "Inicializar um disco vazio / RAW", ["PtConvert"] = "Converter MBR ↔ GPT (apaga o disco)", ["PtCheck"] = "Verificar sistema de arquivos (CHKDSK)", ["PtActive"] = "Definir a primeira partição como ativa (flag de inicialização MBR)", ["PtFindLost"] = "Procurar partições perdidas (varredura somente leitura)", ["PtConfirmBody"] = "{0} neste disco?\n\n    Disco {1} — {2} — {3}\n\nAtualmente contém:\n{4}\n\n⚠ Tudo será APAGADO. Não pode ser desfeito.", ["PtWorking"] = "{0} no disco selecionad