			["MbBootHelp"] = "\n\nHoe ervan op te starten: sluit de schijf aan op de doel-pc, zet hem aan en open het opstartmenu (meestal F12, F9, Esc of F2 direct na het inschakelen), kies daarna deze USB/SSD. De eerste keer opstarten duurt enkele minuten terwijl Windows de stuurprogramma's instelt.",
			["MbBitLockerNote"] = "\n\nLet op: BitLocker is nog op de achtergrond aan het versleutelen — houd de schijf aangesloten totdat deze 100% bereikt (manage-bde -status), anders voltooit het bij de eerste keer opstarten van de kloon.",
			["MbReinstallConfirm"] = "Opnieuw installeren WIST alle bestanden (inclusief uw ISO's) op Schijf {0}. Doorgaan?",
			["Mb028"] = "DriveForge voert de capaciteitstest niet uit op een systeemschijf.",
			["Mb042"] = "Selecteer eerst de te formatteren schijf (Te testen schijf).",
			["Mb027"] = "Selecteer eerst de te testen schijf (Te testen schijf).",
			["Mb045"] = "Herstart DriveForge als administrator om partities te beheren.",
			["Mb022"] = "Herstart DriveForge als administrator om schijven te wissen.",
			["MbMultiBootDone"] = "Klaar! Schijf {0} is nu een multi-boot USB.\n\nKopieer uw ISO-bestanden naar de zojuist geopende \"Ventoy\"-schijf — voeg er zoveel toe als erop passen (Windows, Linux, reparatietools).\n\nStart een willekeurige pc op vanaf deze schijf en kies een ISO uit het menu. Tip: gebruik Opstarttest om te controleren of hij opstart.",
			["Mb021"] = "Dit is een systeemschijf — DriveForge wist deze niet.",
			["MbIsoTooBig"] = "De ISO ({0}) is groter dan de schijf ({1}).",
			["Mb018"] = "Dit is een systeemschijf — deze kan niet worden uitgeworpen.",
			["Mb015"] = "Er is nog geen rapport beschikbaar.",
			["Mb016"] = "Deze schijf heeft geen stationsletter. Formatteer deze eerst en wis daarna de vrije ruimte.",
			["Mb013"] = "De wachtwoorden komen niet overeen.",
			["MbNoFreeWipe"] = "Er is bijna geen vrije ruimte om te wissen op {0}:.",
			["MbSchedCreated"] = "Geplande taak \"DriveForge Auto Clone\" gemaakt.\n\nDeze kloont deze pc naar '{0}' {1} om 02:00, zolang die schijf is aangesloten.\n\nVerwijder hem op elk moment via Windows Task Scheduler (of hij wordt vervangen als u opnieuw een planning maakt).",
			["MbWipeFreeConfirm"] = "Vrije ruimte op {0}: wissen?\n\nUw bestaande bestanden worden NIET aangeraakt. DriveForge vult de {1} vrije ruimte met overschrijfgegevens ({2} doorgang(en)) en verwijdert deze daarna, zodat eerder verwijderde bestanden niet meer kunnen worden hersteld.\n\nDe schijf is tijdens het proces tijdelijk vol. Doorgaan?",
			["Mb038"] = "Multi-boot draait op de gratis, opensource Ventoy-engine (GPL-3.0). DriveForge moet deze eenmalig downloaden (~16 MB); daarna wordt deze in de cache opgeslagen voor offline gebruik.\n\nNu downloaden?",
			["Mb035"] = "Plak een directe http(s)-link naar een ISO-bestand.",
			["Mb032"] = "Herstart DriveForge als administrator om de opstarttest uit te voeren.",
			["Mb020"] = "Selecteer eerst de te wissen schijf (Te testen schijf).",
			["MbBootTestOfflineWarn"] = "De opstarttest is voltooid, maar het weer online zetten van Schijf {0} is mogelijk mislukt.\n\nAls de schijf ontbreekt in Explorer, schakel deze opnieuw in via Disk Management, of voer in een admin PowerShell uit:\n    Set-Disk -Number {0} -IsOffline $false",
			["MbWriteIsoConfirm"] = "Deze ISO naar de USB schrijven als opstartbare afbeelding?\n\n    ISO: {0} ({1})\n    Naar: Schijf {2} — {3} — {4}\n\nDeze schijf bevat momenteel:\n{5}\n\n⚠ Alles op de schijf wordt GEWIST. (Werkt voor Linux en andere isohybrid-ISO's; een Windows-ISO kan beter worden gemaakt met \"Create Windows USB\".)",
			["Mb041"] = "Niets geselecteerd.",
			["MbHyperV"] = "Voor de opstarttest is de Hyper-V-functie nodig, die niet is ingeschakeld op deze pc.\n\n\"Turn Windows features on or off\" openen zodat u Hyper-V kunt inschakelen? (Na het inschakelen is een herstart vereist.)",
			["Mb044"] = "Herstart DriveForge als administrator om schijven te formatteren.",
			["MbBootTestConfirm"] = "Deze schijf testen door op te starten in een virtuele machine?\n\n    Schijf {0} — {1} — {2}\n\nDriveForge gaat:\n• deze schijf offline halen (zodat de VM hem kan gebruiken),\n• een tijdelijke {3} VM starten die ervan opstart,\n• een venster openen zodat u het opstarten kunt bekijken.\n\nKijk alleen of het opstartmenu / logo verschijnt — voer GEEN installatieprogramma uit binnen de VM. Kom terug als u klaar bent en klik op OK om de test te stoppen en de schijf weer online te zetten.",
			["Mb019"] = "De schijf is leeggemaakt en uitgeworpen.\n\nAls Windows deze nog toont, wacht dan even en koppel hem los. (Interne SATA/NVMe-schijven kunnen mogelijk niet worden uitgeworpen — dat is normaal.)",
			["MbSurfaceConfirm"] = "Een alleen-lezen oppervlaktetest uitvoeren op:\n    Schijf {0} — {1} — {2}\n\nDriveForge leest elke sector om beschadigde/onleesbare blokken te vinden. Er wordt niets geschreven. Grote schijven kunnen even duren — gebruik Stop om te annuleren.",
			["MbVmRunning"] = "De opstarttest-VM draait en het venster is geopend.\n\n• Als u het opstartlogo / -menu van de schijf ziet, start hij correct op. ✓\n• Een zwart scherm of \"no bootable device\" betekent dat hij niet opstart — probeer de andere firmwaremodus (UEFI ↔ Legacy BIOS).\n\nKlik op OK wanneer u klaar bent om de test te stoppen en de schijf weer online te zetten.",
			["MbMultiBootTitle"] = "DriveForge — multi-boot USB",
			["Mb017"] = "Selecteer eerst de te verwijderen schijf (stap 3).",
			["MbShredTitle"] = "DriveForge — veilig versnipperen",
			["MbCapacityTitle"] = "DriveForge — capaciteitstest",
			["MbCapacityConfirm"] = "De WERKELIJKE capaciteit verifiëren van:\n    {0} ({1}:) — claimt {2}\n\nDit schrijft ~{3} aan testgegevens naar de VRIJE ruimte, leest deze terug ter verificatie en verwijdert ze daarna. Uw bestaande bestanden worden NIET aangeraakt. Voer dit voor een volledige controle uit op een lege schijf.\n\nDoorgaan?",
			["MbDownloaded"] = "Gedownload:\n    {0}\n\nDe map nu openen?",
			["Mb001"] = "Selecteer eerst de doelschijf (stap 3).",
			["Mb002"] = "Kon het toepassingspad om te plannen niet bepalen.",
			["BzBootVm"] = "Opstarttest-VM voor Schijf {0} starten...",
			["MbUsbDone"] = "USB-aanmaak voltooid.",
			["Mb007"] = "Selecteer eerst een doel-USB/SSD.",
			["BzWiping"] = "Schijf {0} ({1}) wissen...",
			["MbSurfaceTitle"] = "DriveForge — oppervlaktetest",
			["Mb008"] = "De geselecteerde schijf is gemarkeerd als systeem-/opstartschijf. DriveForge formatteert deze niet.",
			["Mb026"] = "De geschreven afbeelding nu verifiëren?\n\nDriveForge leest de gegevens terug van de schijf en vergelijkt deze byte voor byte met de ISO om te bevestigen dat het correct is geschreven (aanbevolen).",
			["BzCapacity"] = "Werkelijke capaciteit van {0}: testen...",
			["Mb025"] = "Dit lijkt een Windows / WinPE ISO te zijn.\n\nWindows-ISO's zijn niet \"isohybrid\", dus een ervan als ruwe afbeelding schrijven start meestal NIET op. Gebruik in plaats daarvan de taak \"Create Windows USB\" voor een juiste opstartbare Windows USB.\n\nToch ruw schrijven?",
			["Mb003"] = "Selecteer eerst een Windows ISO / WIM / ESD (stap 2).",
			["BzVerify"] = "Schijf {0} verifiëren...",
			["MbTestBootTitle"] = "DriveForge — opstarttest",
			["MbBackupCreated"] = "Back-upafbeelding gemaakt:\n\n{0}  ({1})\n\nOm deze later te herstellen: kies \"Geavanceerd: volledige schijfafbeelding herstellen\", selecteer deze .wim en kies de doelschijf.",
			["MbFormatConfirm"] = "Deze schijf formatteren (wissen)?\n\n    Schijf {0} — {1} — {2}\n\nDeze schijf bevat momenteel:\n{3}\n\n⚠ AL het bovenstaande wordt permanent GEWIST.",
			["MbSchedDaily"] = "elke dag",
			["MbBackupNoSpace"] = "Onvoldoende vrije ruimte op de locatie waar u de afbeelding opslaat.\n\nGeschat benodigde ruimte: ~{0}\nVrij op bestemming: {1}",
			["MbWriteIsoTitle"] = "DriveForge — ISO schrijven",
			["Mb014"] = "BitLocker-wachtwoorden moeten minstens 8 tekens bevatten (of laat beide leeg voor alleen een herstelsleutel).",
