			["MbShredConfirm"] = "Trwale zniszczyć {0} plik(ów)?\n\nZawartość każdego pliku zostanie nadpisana ({1} przebieg(ów)), a następnie usunięta. Tej operacji nie można cofnąć.\n\n(Uwaga: w przypadku dysków SSD/pamięci flash USB wyrównywanie zużycia oznacza, że kilka kopii może fizycznie pozostać; aby uzyskać absolutną pewność w przypadku pamięci flash, wykonaj również pełne czyszczenie dysku lub użyj funkcji Secure Erase dysku.)",
			["MbSchedWeekly"] = "w każdą niedzielę",
			["Mb037"] = "Włóż nośnik USB, którego chcesz użyć, a następnie spróbuj ponownie.",
			["Mb040"] = "Uruchom ponownie DriveForge jako administrator, aby przeprowadzić test powierzchni.",
			["Mb034"] = "Nie udało się automatycznie znaleźć aktualnego łącza do pobierania. Użyj zamiast tego przycisku na oficjalnej stronie pobierania.",
			["MbFormatDone"] = "Gotowe. Dysk {0} został sformatowany jako {1} i jest gotowy do użycia.",
			["Mb031"] = "To jest dysk systemowy — DriveForge nie przeprowadzi na nim testu rozruchu.",
			["MbBootHelp"] = "\n\nJak z niego uruchomić: podłącz dysk do docelowego komputera, włącz go i otwórz menu rozruchu (zwykle F12, F9, Esc lub F2 zaraz po włączeniu), a następnie wybierz ten USB/SSD. Pierwszy rozruch trwa kilka minut, gdy Windows konfiguruje sterowniki.",
			["MbBitLockerNote"] = "\n\nUwaga: BitLocker nadal szyfruje w tle — pozostaw dysk podłączony, dopóki nie osiągnie 100% (manage-bde -status), w przeciwnym razie zakończy szyfrowanie przy pierwszym rozruchu klona.",
			["MbReinstallConfirm"] = "Ponowna instalacja WYMAŻE wszystkie pliki (w tym Twoje obrazy ISO) na dysku {0}. Kontynuować?",
			["Mb028"] = "DriveForge nie uruchomi testu pojemności na dysku systemowym.",
			["Mb042"] = "Najpierw wybierz dysk do sformatowania (Dysk do testu).",
			["Mb027"] = "Najpierw wybierz dysk do testu (Dysk do testu).",
			["Mb045"] = "Uruchom ponownie DriveForge jako administrator, aby zarządzać partycjami.",
			["Mb022"] = "Uruchom ponownie DriveForge jako administrator, aby czyścić dyski.",
			["MbMultiBootDone"] = "Gotowe! Dysk {0} jest teraz wielorozruchowym nośnikiem USB.\n\nSkopiuj swoje pliki ISO na dysk \"Ventoy\", który właśnie się otworzył — dodaj tyle, ile się zmieści (Windows, Linux, narzędzia ratunkowe).\n\nUruchom dowolny komputer z tego dysku i wybierz obraz ISO z menu. Wskazówka: użyj funkcji Test rozruchu, aby sprawdzić, czy się uruchamia.",
			["Mb021"] = "To jest dysk systemowy — DriveForge go nie wyczyści.",
			["MbIsoTooBig"] = "Obraz ISO ({0}) jest większy niż dysk ({1}).",
			["Mb018"] = "To jest dysk systemowy — nie można go wysunąć.",
			["Mb015"] = "Żaden raport nie jest jeszcze dostępny.",
			["Mb016"] = "Ten dysk nie ma litery dysku. Najpierw go sformatuj, a następnie wyczyść jego wolne miejsce.",
			["Mb013"] = "Hasła nie są zgodne.",
			["MbNoFreeWipe"] = "Na {0}: prawie nie ma wolnego miejsca do wyczyszczenia.",
			["MbSchedCreated"] = "Utworzono zaplanowane zadanie \"DriveForge Auto Clone\".\n\nBędzie ono klonować ten komputer do '{0}' {1} o godzinie 02:00, o ile ten dysk jest podłączony.\n\nMożesz je usunąć w dowolnym momencie z Task Scheduler (lub zostanie zastąpione, jeśli zaplanujesz ponownie).",
			["MbWipeFreeConfirm"] = "Wyczyścić wolne miejsce na {0}:?\n\nTwoje istniejące pliki NIE zostaną naruszone. DriveForge wypełnia {1} wolnego miejsca danymi nadpisującymi ({2} przebieg(ów)), a następnie je usuwa, dzięki czemu wcześniej usunięte pliki nie będą mogły zostać odzyskane.\n\nDysk będzie tymczasowo zapełniony podczas tego procesu. Kontynuować?",
			["Mb038"] = "Tryb wielorozruchowy działa w oparciu o darmowy silnik Ventoy o otwartym kodzie źródłowym (GPL-3.0). DriveForge musi go raz pobrać (~16 MB); następnie jest on buforowany do użytku offline.\n\nPobrać go teraz?",
			["Mb035"] = "Wklej bezpośrednie łącze http(s) do pliku ISO.",
			["Mb032"] = "Uruchom ponownie DriveForge jako administrator, aby przeprowadzić test rozruchu.",
			["Mb020"] = "Najpierw wybierz dysk do wyczyszczenia (Dysk do testu).",
			["MbBootTestOfflineWarn"] = "Test rozruchu zakończył się, ale ponowne przełączenie dysku {0} w tryb online mogło się nie powieść.\n\nJeśli dysku brakuje w Explorer, włącz go ponownie w Disk Management lub uruchom w PowerShell z uprawnieniami administratora:\n    Set-Disk -Number {0} -IsOffline $false",
			["MbWriteIsoConfirm"] = "Zapisać ten obraz ISO na nośniku USB jako obraz rozruchowy?\n\n    ISO: {0} ({1})\n    Do: dysk {2} — {3} — {4}\n\nTen dysk obecnie zawiera:\n{5}\n\n⚠ Wszystko na dysku zostanie WYMAZANE. (Działa dla obrazów ISO systemu Linux i innych typu isohybrid; obraz ISO systemu Windows lepiej tworzyć za pomocą \"Create Windows USB\".)",
			["Mb041"] = "Nic nie wybrano.",
			["MbHyperV"] = "Test rozruchu wymaga funkcji Hyper-V, która nie jest włączona na tym komputerze.\n\nOtworzyć \"Turn Windows features on or off\", aby umożliwić włączenie Hyper-V? (Po włączeniu wymagane jest ponowne uruchomienie komputera.)",
			["Mb044"] = "Uruchom ponownie DriveForge jako administrator, aby formatować dyski.",
			["MbBootTestConfirm"] = "Przetestować rozruch tego dysku w maszynie wirtualnej?\n\n    Dysk {0} — {1} — {2}\n\nDriveForge:\n• przełączy ten dysk w tryb offline (aby maszyna wirtualna mogła go używać),\n• uruchomi tymczasową maszynę wirtualną {3}, która z niego startuje,\n• otworzy okno, abyś mógł obserwować rozruch.\n\nWystarczy, że sprawdzisz, czy dociera do menu rozruchu / logo — NIE uruchamiaj instalatora wewnątrz maszyny wirtualnej. Gdy skończysz, wróć tutaj i kliknij OK, aby zatrzymać test i ponownie przełączyć dysk w tryb online.",
			["Mb019"] = "Dysk został opróżniony i wysunięty.\n\nJeśli Windows nadal go pokazuje, zaczekaj chwilę, a następnie odłącz go. (Wewnętrzne dyski SATA/NVMe mogą się nie wysunąć — to normalne.)",
			["MbSurfaceConfirm"] = "Uruchomić test powierzchni tylko do odczytu na:\n    dysku {0} — {1} — {2}\n\nDriveForge odczytuje każdy sektor, aby znaleźć uszkodzone/nieczytelne bloki. Nic nie jest zapisywane. Duże dyski mogą wymagać trochę czasu — użyj Stop, aby anulować.",
			["MbVmRunning"] = "Maszyna wirtualna testu rozruchu jest uruchomiona i jej okno zostało otwarte.\n\n• Jeśli widzisz logo / menu rozruchu dysku, uruchamia się on poprawnie. ✓\n• Czarny ekran lub komunikat \"no bootable device\" oznacza, że się nie uruchamia — wypróbuj inny tryb oprogramowania układowego (UEFI ↔ Legacy BIOS).\n\nKliknij OK, gdy skończysz, aby zatrzymać test i ponownie przełączyć dysk w tryb online.",
			["MbMultiBootTitle"] = "DriveForge — wielorozruchowy USB",
			["Mb017"] = "Najpierw wybierz dysk do usunięcia (krok 3).",
			["MbShredTitle"] = "DriveForge — bezpieczne niszczenie",
			["MbCapacityTitle"] = "DriveForge — test pojemności",
			["MbCapacityConfirm"] = "Zweryfikować RZECZYWISTĄ pojemność:\n    {0} ({1}:) — deklaruje {2}\n\nZapisuje to ~{3} danych testowych w WOLNYM miejscu, odczytuje je z powrotem w celu weryfikacji, a następnie usuwa. Twoje istniejące pliki NIE zostaną naruszone. Aby uzyskać pełne sprawdzenie, uruchom test na pustym dysku.\n\nKontynuować?",
			["MbDownloaded"] = "Pobrano:\n    {0}\n\nOtworzyć teraz folder?",
			["Mb001"] = "Najpierw wybierz dysk docelowy (krok 3).",
			["Mb002"] = "Nie udało się ustalić ścieżki aplikacji do zaplanowania.",
			["BzBootVm"] = "Uruchamianie maszyny wirtualnej testu rozruchu dla dysku {0}...",
			["MbUsbDone"] = "Tworzenie nośnika USB zakończone.",
			["Mb007"] = "Najpierw wybierz docelowy USB/SSD.",
			["BzWiping"] = "Czyszczenie dysku {0} ({1})...",
			["MbSurfaceTitle"] = "DriveForge — test powierzchni",
			["Mb008"] = "Wybrany dysk jest oznaczony jako dysk systemowy/rozruchowy. DriveForge go nie sformatuje.",
			["Mb026"] = "Zweryfikować teraz zapisany obraz?\n\nDriveForge odczyta dane z dysku z powrotem i porówna je bajt po bajcie z obrazem ISO, aby potwierdzić, że został zapisany poprawnie (zalecane).",
			["BzCapacity"] = "Testowanie rzeczywistej pojemności {0}:...",
			["Mb025"] = "To wygląda na obraz ISO systemu Windows / WinPE.\n\nObrazy ISO systemu Windows nie są typu \"isohybrid\", więc zapisanie jednego jako surowego obrazu zazwyczaj NIE umożliwia rozruchu. Aby utworzyć prawidłowy rozruchowy nośnik USB z systemem Windows, użyj zamiast tego zadania \"Create Windows USB\".\n\nMimo to zapisać go jako surowy obraz?",
			["Mb003"] = "Najpierw wybierz Windows ISO / WIM / ESD (krok 2).",
			["BzVerify"] = "Weryfikowanie dysku {0}...",
			["MbTestBootTitle"] = "DriveForge — test rozruchu",
			["MbBackupCreated"] = "Utworzono obraz kopii zapasowej:\n\n{0}  ({1})\n\nAby przywrócić go później: wybierz \"Advanced: restore full disk image\", wskaż ten plik .wim i wybierz dysk docelowy.",
			["MbFormatConfirm"] = "Sformatować (wymazać) ten dysk?\n\n    Dysk {0} — {1} — {2}\n\nTen dysk obecnie zawiera:\n{3}\n\n⚠ WSZYSTKO powyżej zostanie trwale WYMAZANE.",
			["MbSchedDaily"] = "codziennie",
			["MbBackupNoSpace"] = "Za mało wolnego miejsca tam, gdzie zapisujesz obraz.\n\nSzacowane potrzebne miejsce: ~{0}\nWolne w miejscu docelowym: {1}",
			["MbWriteIsoTitle"] = "DriveForge — zapis ISO",
