			["Mb039"] = "Najpierw wybierz dysk do testu.",
			["Mb036"] = "Uruchom ponownie DriveForge jako administrator, aby utworzyć wielorozruchowy nośnik USB.",
			["Mb006"] = "Zatrzymać bieżącą operację? Nośnik USB może być niedokończony i wymagać ponownego sformatowania.",
