			["MbWipeTitle"] = "DriveForge — güvenli silme",
			["Mb030"] = "Test için yeterli boş alan yok. Önce sürücüyü boşaltın veya biçimlendirin.",
			["MbWipeConfirm"] = "Bu sürücü GÜVENLE SİLİNSİN mi (silinsin)?\n\n    Disk {0} — {1} — {2}\n\nBu disk şu anda şunları içeriyor:\n{3}\n\n⚠ Her sektörün ÜZERİNE YAZILACAK. Veriler kurtarılamayacak. Bu işlem geri alınamaz.",
			["MbShredConfirm"] = "{0} dosya kalıcı olarak parçalansın mı?\n\nHer dosyanın içeriğinin üzerine yazılacak ({1} geçiş) ve ardından silinecek. Bu işlem geri alınamaz.\n\n(Not: SSD'lerde/USB belleklerde aşınma dengeleme nedeniyle birkaç kopya fiziksel olarak kalabilir; bellekte kesin kesinlik için tam sürücü Silme işlemi de yapın veya sürücünün Güvenli Silme özelliğini kullanın.)",
			["MbSchedWeekly"] = "her Pazar",
			["Mb037"] = "Kullanmak istediğiniz USB sürücüsünü takın, sonra tekrar deneyin.",
			["Mb040"] = "Yüzey testi çalıştırmak için DriveForge'u yönetici olarak yeniden başlatın.",
			["Mb034"] = "Güncel bir indirme bağlantısı otomatik olarak bulunamadı. Bunun yerine resmi indirme sayfası düğmesini kullanın.",
			["MbFormatDone"] = "Tamamlandı. Disk {0}, {1} olarak biçimlendirildi ve kullanıma hazır.",
			["Mb031"] = "Bu bir sistem diski — DriveForge bunu önyükleme testine tabi tutmaz.",
			["MbBootHelp"] = "\n\nNasıl başlatılır: sürücüyü hedef PC'ye takın, gücü açın ve önyükleme menüsünü açın (genellikle güç açıldıktan hemen sonra F12, F9, Esc veya F2), ardından bu USB/SSD'yi seçin. Windows sürücüleri ayarlarken ilk önyükleme birkaç dakika sürer.",
			["MbBitLockerNote"] = "\n\nNot: BitLocker arka planda hâlâ şifreliyor — %100'e ulaşana kadar sürücüyü bağlı tutun (manage-bde -status) veya klonun ilk önyüklemesinde tamamlanır.",
			["MbReinstallConfirm"] = "Yeniden yükleme, Disk {0} üzerindeki tüm dosyaları (ISO'larınız dahil) SİLECEK. Devam edilsin mi?",
			["Mb028"] = "DriveForge bir sistem diskinde kapasite testi çalıştırmaz.",
			["Mb042"] = "Önce biçimlendirilecek sürücüyü seçin (Test edilecek sürücü).",
			["Mb027"] = "Önce test edilecek sürücüyü seçin (Test edilecek sürücü).",
			["Mb045"] = "Bölümleri yönetmek için DriveForge'u yönetici olarak yeniden başlatın.",
			["Mb022"] = "Sürücüleri silmek için DriveForge'u yönetici olarak yeniden başlatın.",
			["MbMultiBootDone"] = "Tamamlandı! Disk {0} artık çoklu önyükleme USB'si.\n\nISO dosyalarınızı yeni açılan \"Ventoy\" sürücüsüne kopyalayın — sığdığı kadar ekleyin (Windows, Linux, kurtarma araçları).\n\nBu sürücüden herhangi bir PC'yi önyükleyin ve menüden bir ISO seçin. İpucu: önyükleme yaptığını doğrulamak için Test boot'u kullanın.",
			["Mb021"] = "Bu bir sistem diski — DriveForge bunu silmez.",
			["MbIsoTooBig"] = "ISO ({0}) sürücüden ({1}) daha büyük.",
			["Mb018"] = "Bu bir sistem diski — çıkarılamaz.",
			["Mb015"] = "Henüz bir rapor mevcut değil.",
			["Mb016"] = "Bu sürücünün sürücü harfi yok. Önce biçimlendirin, sonra boş alanını silin.",
			["Mb013"] = "Parolalar eşleşmiyor.",
			["MbNoFreeWipe"] = "{0}: üzerinde silinecek neredeyse hiç boş alan yok.",
			["MbSchedCreated"] = "\"DriveForge Auto Clone\" zamanlanmış görevi oluşturuldu.\n\nBu PC'yi, ilgili sürücü bağlı olduğu sürece '{0}' konumuna {1} saat 02:00'de klonlayacak.\n\nDilediğiniz zaman Windows Task Scheduler'dan kaldırın (veya yeniden zamanlarsanız değiştirilir).",
			["MbWipeFreeConfirm"] = "{0}: üzerindeki boş alan silinsin mi?\n\nMevcut dosyalarınıza DOKUNULMAZ. DriveForge {1} boş alanı üzerine yazma verisiyle doldurur ({2} geçiş) ve ardından bunu kaldırır, böylece daha önce sildiğiniz dosyalar artık kurtarılamaz.\n\nİşlem sırasında sürücü geçici olarak dolu olacaktır. Devam edilsin mi?",
			["Mb038"] = "Çoklu önyükleme, ücretsiz ve açık kaynaklı Ventoy motoruyla (GPL-3.0) çalışır. DriveForge'un onu bir kez indirmesi gerekir (~16 MB); ardından çevrimdışı kullanım için önbelleğe alınır.\n\nŞimdi indirilsin mi?",
			["Mb035"] = "Bir ISO dosyasına doğrudan http(s) bağlantısı yapıştırın.",
			["Mb032"] = "Önyükleme testini çalıştırmak için DriveForge'u yönetici olarak yeniden başlatın.",
			["Mb020"] = "Önce silinecek sürücüyü seçin (Test edilecek sürücü).",
			["MbBootTestOfflineWarn"] = "Önyükleme testi tamamlandı ancak Disk {0} yeniden çevrimiçi yapılırken hata oluşmuş olabilir.\n\nSürücü Explorer'da görünmüyorsa, Disk Management'ta yeniden etkinleştirin veya bir yönetici PowerShell'de çalıştırın:\n    Set-Disk -Number {0} -IsOffline $false",
			["MbWriteIsoConfirm"] = "Bu ISO, USB'ye önyüklenebilir bir imaj olarak yazılsın mı?\n\n    ISO: {0} ({1})\n    Hedef: Disk {2} — {3} — {4}\n\nBu disk şu anda şunları içeriyor:\n{5}\n\n⚠ Diskteki her şey SİLİNECEK. (Linux ve diğer isohybrid ISO'lar için çalışır; bir Windows ISO için \"Create Windows USB\" daha iyidir.)",
			["Mb041"] = "Hiçbir şey seçilmedi.",
			["MbHyperV"] = "Test önyüklemesi, bu PC'de etkin olmayan Hyper-V özelliğine ihtiyaç duyar.\n\nHyper-V'yi etkinleştirebilmeniz için \"Turn Windows features on or off\" açılsın mı? (Etkinleştirdikten sonra yeniden başlatma gereklidir.)",
			["Mb044"] = "Sürücüleri biçimlendirmek için DriveForge'u yönetici olarak yeniden başlatın.",
			["MbBootTestConfirm"] = "Bu sürücü sanal makinede önyükleme testine tabi tutulsun mu?\n\n    Disk {0} — {1} — {2}\n\nDriveForge şunları yapacak:\n• bu diski çevrimdışı alır (VM'in onu kullanabilmesi için),\n• ondan önyükleme yapan geçici bir {3} VM başlatır,\n• önyüklemesini izleyebilmeniz için bir pencere açar.\n\nYalnızca önyükleme menüsüne / logosuna ulaştığını izleyin — VM içinde bir yükleyici ÇALIŞTIRMAYIN. İşiniz bittiğinde buraya geri dönün ve testi durdurup diski yeniden çevrimiçi yapmak için OK'a tıklayın.",
			["Mb019"] = "Sürücü temizlendi ve çıkarıldı.\n\nWindows hâlâ gösteriyorsa, bir an bekleyin, sonra çıkarın. (Dahili SATA/NVMe diskleri çıkarılamayabilir — bu normaldir.)",
			["MbSurfaceConfirm"] = "Şunun üzerinde salt okunur yüzey testi çalıştır:\n    Disk {0} — {1} — {2}\n\nDriveForge, bozuk/okunamayan blokları bulmak için her sektörü okur. Hiçbir şey yazılmaz. Büyük sürücüler biraz zaman alabilir — iptal etmek için Stop'u kullanın.",
			["MbVmRunning"] = "Önyükleme testi VM'i çalışıyor ve penceresi açıldı.\n\n• Sürücünün önyükleme logosunu / menüsünü görüyorsanız, doğru önyükleniyor demektir. ✓\n• Siyah ekran veya \"no bootable device\" önyükleme yapmadığı anlamına gelir — diğer ürün yazılımı modunu deneyin (UEFI ↔ Legacy BIOS).\n\nİşiniz bittiğinde testi durdurup diski yeniden çevrimiçi yapmak için OK'a tıklayın.",
			["MbMultiBootTitle"] = "DriveForge — çoklu önyükleme USB'si",
			["Mb017"] = "Önce kaldırılacak sürücüyü seçin (adım 3).",
			["MbShredTitle"] = "DriveForge — güvenli parçalama",
			["MbCapacityTitle"] = "DriveForge — kapasite testi",
			["MbCapacityConfirm"] = "Şunun GERÇEK kapasitesini doğrula:\n    {0} ({1}:) — iddia edilen {2}\n\nBu işlem BOŞ alana ~{3} test verisi yazar, doğrulamak için geri okur ve sonra siler. Mevcut dosyalarınıza DOKUNULMAZ. Eksiksiz bir kontrol için boş bir sürücüde çalıştırın.\n\nDevam edilsin mi?",
