			["Mb034"] = "Не вдалося автоматично знайти актуальне посилання для завантаження. Скористайтеся натомість кнопкою на офіційній сторінці завантаження.",
			["MbFormatDone"] = "Готово. Диск {0} відформатовано як {1}, і він готовий до використання.",
			["Mb031"] = "Це системний диск — DriveForge не виконуватиме тест завантаження на ньому.",
			["MbBootHelp"] = "\n\nЯк завантажитися з нього: під’єднайте диск до цільового ПК, увімкніть його та відкрийте меню завантаження (зазвичай F12, F9, Esc або F2 одразу після ввімкнення), потім виберіть цей USB/SSD. Перше завантаження триває кілька хвилин, поки Windows налаштовує драйвери.",
			["MbBitLockerNote"] = "\n\nПримітка: BitLocker усе ще шифрує у фоновому режимі — тримайте диск підключеним, доки він не досягне 100% (manage-bde -status), інакше шифрування завершиться під час першого завантаження клона.",
			["MbReinstallConfirm"] = "Перевстановлення СТЕРЕ всі файли (зокрема ваші ISO) на диску {0}. Продовжити?",
			["Mb028"] = "DriveForge не виконуватиме тест ємності на системному диску.",
			["Mb042"] = "Спочатку виберіть диск для форматування (Диск для тестування).",
			["Mb027"] = "Спочатку виберіть диск для тестування (Диск для тестування).",
			["Mb045"] = "Перезапустіть DriveForge від імені адміністратора, щоб керувати розділами.",
			["Mb022"] = "Перезапустіть DriveForge від імені адміністратора, щоб очищати диски.",
			["MbMultiBootDone"] = "Готово! Диск {0} тепер є мультизавантажувальним USB.\n\nСкопіюйте свої файли ISO на диск \"Ventoy\", який щойно відкрився — додайте стільки, скільки вмістить (Windows, Linux, рятувальні інструменти).\n\nЗавантажте будь-який ПК із цього диска та виберіть ISO з меню. Порада: скористайтеся тестом завантаження, щоб перевірити, чи він завантажується.",
			["Mb021"] = "Це системний диск — DriveForge не очищатиме його.",
			["MbIsoTooBig"] = "ISO ({0}) більший за диск ({1}).",
			["Mb018"] = "Це системний диск — його не можна вилучити.",
			["Mb015"] = "Звіт ще недоступний.",
			["Mb016"] = "У цього диска немає літери. Спочатку відформатуйте його, потім очистіть його вільний простір.",
			["Mb013"] = "Паролі не збігаються.",
			["MbNoFreeWipe"] = "На {0}: майже немає вільного місця для очищення.",
			["MbSchedCreated"] = "Заплановане завдання \"DriveForge Auto Clone\" створено.\n\nВоно клонуватиме цей ПК на «{0}» {1} о 02:00, доки цей диск підключено.\n\nВидалити його можна будь-коли через \"Task Scheduler\" Windows (або воно замінюється, якщо запланувати знову).",
			["MbWipeFreeConfirm"] = "Очистити вільний простір на {0}:?\n\nВаші наявні файли НЕ зачіпаються. DriveForge заповнює {1} вільного місця даними перезапису ({2} прохід(ів)), а потім видаляє їх, тож раніше видалені файли більше неможливо відновити.\n\nПід час процесу диск буде тимчасово заповнений. Продовжити?",
			["Mb038"] = "Мультизавантаження працює на безкоштовному рушії Ventoy з відкритим кодом (GPL-3.0). DriveForge потрібно завантажити його один раз (~16 МБ); потім він кешується для офлайн-використання.\n\nЗавантажити його зараз?",
			["Mb035"] = "Вставте пряме посилання http(s) на файл ISO.",
			["Mb032"] = "Перезапустіть DriveForge від імені адміністратора, щоб запустити тест завантаження.",
			["Mb020"] = "Спочатку виберіть диск для очищення (Диск для тестування).",
			["MbBootTestOfflineWarn"] = "Тест завантаження завершено, але повернення диска {0} в онлайн могло не вдатися.\n\nЯкщо диск відсутній у Explorer, увімкніть його знову в \"Disk Management\" або виконайте в адміністраторському PowerShell:\n    Set-Disk -Number {0} -IsOffline $false",
			["MbWriteIsoConfirm"] = "Записати цей ISO на USB як завантажувальний образ?\n\n    ISO: {0} ({1})\n    На: диск {2} — {3} — {4}\n\nЗараз цей диск містить:\n{5}\n\n⚠ Усе на диску буде СТЕРТО. (Працює для Linux та інших isohybrid ISO; ISO Windows краще створювати через \"Create Windows USB\".)",
			["Mb041"] = "Нічого не вибрано.",
			["MbHyperV"] = "Для тесту завантаження потрібна функція Hyper-V, яка не ввімкнена на цьому ПК.\n\nВідкрити \"Turn Windows features on or off\", щоб ви могли ввімкнути Hyper-V? (Після ввімкнення потрібен перезапуск.)",
			["Mb044"] = "Перезапустіть DriveForge від імені адміністратора, щоб форматувати диски.",
			["MbBootTestConfirm"] = "Протестувати завантаження цього диска у віртуальній машині?\n\n    Диск {0} — {1} — {2}\n\nDriveForge виконає такі дії:\n• переведе цей диск в офлайн (щоб VM могла його використати),\n• запустить тимчасову {3} VM, яка завантажується з нього,\n• відкриє вікно, щоб ви могли спостерігати за завантаженням.\n\nПросто простежте, щоб воно дійшло до меню завантаження / логотипа — НЕ запускайте інсталятор усередині VM. Коли закінчите, поверніться сюди й натисніть OK, щоб зупинити тест і повернути диск в онлайн.",
			["Mb019"] = "Дані на диск записано, і його вилучено.\n\nЯкщо Windows усе ще показує його, зачекайте хвильку, а потім від’єднайте. (Внутрішні диски SATA/NVMe можуть не вилучатися — це нормально.)",
			["MbSurfaceConfirm"] = "Виконати тест поверхні лише для читання на:\n    диск {0} — {1} — {2}\n\nDriveForge зчитує кожен сектор, щоб знайти пошкоджені/нечитані блоки. Нічого не записується. Великі диски можуть тестуватися довго — натисніть Stop, щоб скасувати.",
			["MbVmRunning"] = "VM для тесту завантаження запущено, і її вікно відкрилося.\n\n• Якщо ви бачите логотип / меню завантаження диска, він завантажується правильно. ✓\n• Чорний екран або \"no bootable device\" означає, що він не завантажується — спробуйте інший режим прошивки (UEFI ↔ \"Legacy BIOS\").\n\nНатисніть OK, коли закінчите, щоб зупинити тест і повернути диск в онлайн.",
			["MbMultiBootTitle"] = "DriveForge — мультизавантажувальний USB",
			["Mb017"] = "Спочатку виберіть диск для видалення (крок 3).",
			["MbShredTitle"] = "DriveForge — безпечне знищення",
			["MbCapacityTitle"] = "DriveForge — тест ємності",
			["MbCapacityConfirm"] = "Перевірити РЕАЛЬНУ ємність:\n    {0} ({1}:) — заявлено {2}\n\nЦе записує ~{3} тестових даних у ВІЛЬНЕ місце, зчитує їх назад для перевірки, а потім видаляє. Ваші наявні файли НЕ зачіпаються. Для повної перевірки виконайте це на порожньому диску.\n\nПродовжити?",
			["MbDownloaded"] = "Завантажено:\n    {0}\n\nВідкрити папку зараз?",
			["Mb001"] = "Спочатку виберіть цільовий диск (крок 3).",
			["Mb002"] = "Не вдалося визначити шлях до застосунку для планування.",
