			["BzWiping"] = "Очищення диска {0} ({1})...",
			["MbSurfaceTitle"] = "DriveForge — тест поверхні",
			["Mb008"] = "Вибраний диск позначено як системний/завантажувальний. DriveForge не форматуватиме його.",
			["Mb026"] = "Перевірити записаний образ зараз?\n\nDriveForge зчитає дані з диска назад і порівняє їх побайтово з ISO, щоб підтвердити правильність запису (рекомендовано).",
			["BzCapacity"] = "Тестування реальної ємності {0}:...",
			["Mb025"] = "Це схоже на ISO Windows / WinPE.\n\nISO Windows не є «isohybrid», тому запис його як сирого образу зазвичай НЕ завантажується. Для правильного завантажувального USB Windows скористайтеся завданням \"Create Windows USB\".\n\nВсе одно записати як сирий образ?",
			["Mb003"] = "Спочатку виберіть Windows ISO / WIM / ESD (крок 2).",
