			["MbNoFreeWipe"] = "{0}: पर वाइप करने के लिए लगभग कोई खाली जगह नहीं है।",
			["MbSchedCreated"] = "शेड्यूल किया गया कार्य \"DriveForge Auto Clone\" बनाया गया।\n\nयह इस PC को '{0}' पर {1} 02:00 बजे क्लोन करेगा, जब तक वह ड्राइव कनेक्टेड हो।\n\nइसे Windows Task Scheduler से कभी भी हटाएं (या यदि आप फिर से शेड्यूल करते हैं तो यह बदल जाता है)।",
			["MbWipeFreeConfirm"] = "{0}: पर खाली जगह वाइप करें?\n\nआपकी मौजूदा फ़ाइलें छुई नहीं जातीं। DriveForge {1} खाली जगह को ओवरराइट डेटा ({2} पास) से भरता है और फिर उसे हटा देता है, ताकि पहले हटाई गई फ़ाइलें अब रिकवर न की जा सकें।\n\nप्रक्रिया के दौरान ड्राइव अस्थायी रूप से भरी रहेगी। जारी रखें?",
			["Mb038"] = "मल्टी-बूट मुफ़्त, ओपन-सोर्स Ventoy इंजन (GPL-3.0) द्वारा संचालित है। DriveForge को इसे एक बार डाउनलोड करना होगा (~16 MB); इसके बाद यह ऑफ़लाइन उपयोग के लिए कैश हो जाता है।\n\nइसे अभी डाउनलोड करें?",
			["Mb035"] = "किसी ISO फ़ाइल का सीधा http(s) लिंक पेस्ट करें।",
			["Mb032"] = "बूट परीक्षण चलाने के लिए DriveForge को व्यवस्थापक के रूप में फिर से शुरू करें।",
			["Mb020"] = "पहले वाइप करने के लिए ड्राइव चुनें (परीक्षण के लिए ड्राइव)।",
			["MbBootTestOfflineWarn"] = "बूट परीक्षण समाप्त हुआ, लेकिन डिस्क {0} को वापस ऑनलाइन लाना विफल हो सकता है।\n\nयदि ड्राइव Explorer से गायब है, तो इसे Disk Management में फिर से सक्षम करें, या एक व्यवस्थापक PowerShell में चलाएं:\n    Set-Disk -Number {0} -IsOffline $false",
			["MbWriteIsoConfirm"] = "इस ISO को USB पर बूट करने योग्य इमेज के रूप में लिखें?\n\n    ISO: {0} ({1})\n    तक: डिस्क {2} — {3} — {4}\n\nइस डिस्क में अभी निम्नलिखित है:\n{5}\n\n⚠ डिस्क पर सब कुछ मिटा दिया जाएगा। (Linux और अन्य isohybrid ISO के लिए काम करता है; Windows ISO को \"Create Windows USB\" से बनाना बेहतर है।)",
			["Mb041"] = "कुछ भी चयनित नहीं है।",
			["MbHyperV"] = "परीक्षण बूट के लिए Hyper-V सुविधा की आवश्यकता है, जो इस PC पर सक्षम नहीं है।\n\nक्या Hyper-V सक्षम करने के लिए \"Turn Windows features on or off\" खोलें? (इसे सक्षम करने के बाद रीस्टार्ट आवश्यक है।)",
			["Mb044"] = "ड्राइव फ़ॉर्मेट करने के लिए DriveForge को व्यवस्थापक के रूप में फिर से शुरू करें।",
			["MbBootTestConfirm"] = "इस ड्राइव का वर्चुअल मशीन में बूट-परीक्षण करें?\n\n    डिस्क {0} — {1} — {2}\n\nDriveForge निम्नलिखित करेगा:\n• इस डिस्क को ऑफ़लाइन ले जाएगा (ताकि VM इसका उपयोग कर सके),\n• एक अस्थायी {3} VM शुरू करेगा जो इससे बूट होती है,\n• एक विंडो खोलेगा ताकि आप इसे बूट होते देख सकें।\n\nबस यह देखें कि यह बूट मेनू / लोगो तक पहुँचता है — VM के अंदर कोई इंस्टॉलर न चलाएं। जब आप पूरा कर लें, यहाँ वापस आएं और परीक्षण रोकने और डिस्क को वापस ऑनलाइन लाने के लिए OK पर क्लिक करें।",
			["Mb019"] = "ड्राइव को फ्लश करके बाहर निकाल दिया गया है।\n\nयदि Windows अभी भी इसे दिखाता है, तो थोड़ी देर प्रतीक्षा करें, फिर इसे अनप्लग करें। (आंतरिक SATA/NVMe डिस्क बाहर नहीं निकल सकतीं — यह सामान्य है।)",
			["MbSurfaceConfirm"] = "इस पर केवल-पढ़ने योग्य सरफेस परीक्षण चलाएं:\n    डिस्क {0} — {1} — {2}\n\nDriveForge खराब/न पढ़े जा सकने वाले ब्लॉक खोजने के लिए हर सेक्टर को पढ़ता है। कुछ भी नहीं लिखा जाता। बड़ी ड्राइव में समय लग सकता है — रद्द करने के लिए Stop का उपयोग करें।",
			["MbVmRunning"] = "बूट-परीक्षण VM चल रहा है और इसकी विंडो खुल गई है।\n\n• यदि आपको ड्राइव का बूट लोगो / मेनू दिखता है, तो यह सही ढंग से बूट होता है। ✓\n• काली स्क्रीन या \"no bootable device\" का मतलब है कि यह बूट नहीं होता — दूसरे फर्मवेयर मोड (UEFI ↔ Legacy BIOS) को आज़माएं।\n\nपरीक्षण रोकने और डिस्क को वापस ऑनलाइन लाने के लिए, समाप्त होने पर OK पर क्लिक करें।",
			["MbMultiBootTitle"] = "DriveForge — मल्टी-बूट USB",
			["Mb017"] = "पहले हटाने के लिए ड्राइव चुनें (चरण 3)।",
			["MbShredTitle"] = "DriveForge — सुरक्षित श्रेड",
			["MbCapacityTitle"] = "DriveForge — क्षमता परीक्षण",
			["MbCapacityConfirm"] = "इसकी वास्तविक क्षमता सत्यापित करें:\n    {0} ({1}:) — {2} का दावा करता है\n\nयह FREE जगह पर ~{3} परीक्षण डेटा लिखता है, सत्यापित करने के लिए उसे वापस पढ़ता है, फिर उसे हटा देता है। आपकी मौजूदा फ़ाइलें छुई नहीं जातीं। पूर्ण जाँच के लिए, इसे खाली ड्राइव पर चलाएं।\n\nजारी रखें?",
			["MbDownloaded"] = "डाउनलोड किया गया:\n    {0}\n\nअभी फ़ोल्डर खोलें?",
			["Mb001"] = "पहले लक्ष्य ड्राइव चुनें (चरण 3)।",
			["Mb002"] = "शेड्यूल करने के लिए एप्लिकेशन पथ निर्धारित नहीं किया जा सका।",
			["BzBootVm"] = "डिस्क {0} के लिए बूट-परीक्षण VM शुरू किया जा रहा है...",
			["MbUsbDone"] = "USB निर्माण पूर्ण हुआ।",
			["Mb007"] = "पहले एक लक्ष्य USB/SSD चुनें।",
			["BzWiping"] = "डिस्क {0} ({1}) वाइप की जा रही है...",
			["MbSurfaceTitle"] = "DriveForge — सरफेस परीक्षण",
			["Mb008"] = "चुनी गई डिस्क सिस्टम/बूट डिस्क के रूप में चिह्नित है। DriveForge इसे फ़ॉर्मेट नहीं करेगा।",
			["Mb026"] = "अभी लिखी गई इमेज सत्यापित करें?\n\nDriveForge ड्राइव से डेटा को वापस पढ़ेगा और यह पुष्टि करने के लिए कि यह सही ढंग से लिखा गया था, इसकी ISO से बाइट-दर-बाइट तुलना करेगा (अनुशंसित)।",
			["BzCapacity"] = "{0}: की वास्तविक क्षमता का परीक्षण किया जा रहा है...",
			["Mb025"] = "यह एक Windows / WinPE ISO जैसा लगता है।\n\nWindows ISO \"isohybrid\" नहीं होते, इसलिए इसे रॉ इमेज के रूप में लिखने पर आमतौर पर बूट नहीं होता। उचित बूट करने योग्य Windows USB के लिए, इसके बजाय \"Create Windows USB\" कार्य का उपयोग करें।\n\nफिर भी इसे रॉ रूप में लिखें?",
			["Mb003"] = "पहले एक Windows ISO / WIM / ESD चुनें (चरण 2)।",
			["BzVerify"] = "डिस्क {0} सत्यापित की जा रही है...",
			["MbTestBootTitle"] = "DriveForge — परीक्षण बूट",
			["MbBackupCreated"] = "बैकअप इमेज बनाई गई:\n\n{0}  ({1})\n\nबाद में इसे पुनर्स्थापित करने के लिए: \"Advanced: restore full disk image\" चुनें, यह .wim चुनें, और लक्ष्य ड्राइव चुनें।",
			["MbFormatConfirm"] = "इस ड्राइव को फ़ॉर्मेट (मिटाएं) करें?\n\n    डिस्क {0} — {1} — {2}\n\nइस डिस्क में अभी निम्नलिखित है:\n{3}\n\n⚠ उपरोक्त सब कुछ स्थायी रूप से मिटा दिया जाएगा।",
			["MbSchedDaily"] = "हर दिन",
			["MbBackupNoSpace"] = "जहाँ आप इमेज सहेज रहे हैं वहाँ पर्याप्त खाली जगह नहीं है।\n\nअनुमानित आवश्यक जगह: ~{0}\nगंतव्य पर खाली: {1}",
			["MbWriteIsoTitle"] = "DriveForge — ISO लिखें",
			["Mb014"] = "BitLocker पासवर्ड कम से कम 8 वर्णों के होने चाहिए (या केवल रिकवरी-की के लिए दोनों खाली छोड़ दें)।",
			["BzShred"] = "{0} फ़ाइल(ें) श्रेड की जा रही हैं...",
			["Mb011"] = "बैकअप इमेज बनाने के लिए DriveForge को व्यवस्थापक के रूप में फिर से शुरू करें।",
			["Mb012"] = "एक मान्य खाता नाम दर्ज करें (कोई विशेष वर्ण नहीं)।",
			["Mb039"] = "पहले परीक्षण के लिए एक ड्राइव चुनें।",
			["Mb036"] = "मल्टी-बूट USB बनाने के लिए DriveForge को व्यवस्थापक के रूप में फिर से शुरू करें।",
			["Mb006"] = "मौजूदा ऑपरेशन रोकें? USB अधूरा रह सकता है और इसे फिर से फ़ॉर्मेट करने की ज़रूरत पड़ सकती है।",
			["Mb033"] = "पहले सूची से एक डिस्ट्रीब्यूशन चुनें।",
			["MbFormatTitle"] = "DriveForge — ड्राइव फ़ॉर्मेट करें",
			["Mb004"] = "एक ऑपरेशन अभी भी चल रहा है। ऐप बंद करने से USB अधूरा रह सकता है। क्या आप वाकई बंद करना चाहते हैं?",
			["Mb009"] = "पहले एक स्रोत इमेज चुनें।",
			["MbWipeFreeTitle"] = "DriveForge — खाली जगह वाइप करें",
			["Mb010"] = "USB बनाने से पहले DriveForge को व्यवस्थापक के रूप में फिर से शुरू करें।",
			["MbHyperVTitle"] = "DriveForge — Hyper-V आवश्यक",
			["BzWipeFree"] = "{0}: पर खाली जगह वाइप की जा रही है...",
			["Mb043"] = "यह एक सिस्टम डिस्क है — DriveForge इसे फ़ॉर्मेट नहीं करेगा।",
			["BzFormat"] = "डिस्क {0} को {1} के रूप में फ़ॉर्मेट किया जा रहा है...",
			["Mb024"] = "पहले एक ISO इमेज चुनें।",
			["BzWriteIso"] = "डिस्क {0} पर ISO इमेज लिखी जा रही है...",
			["MbMultiBootSetup"] = "डिस्क {0} को मल्टी-बूट USB के रूप में सेट करें?\n\n    {1} — {2}\n\nइस डिस्क में अभी निम्नलिखित है:\n{3}\n\n⚠ ड्राइव मिटा दी जाएगी और Ventoy मल्टी-बूट इंजन के साथ सेट की जाएगी। इसके बाद आप बस उस पर ISO फ़ाइलें कॉपी करते हैं (Windows, Linux, कुछ भी) और बूट के समय मेनू से एक चुनते हैं।",
			["Mb023"] = "अभी एक वाइप प्रमाणपत्र बनाएं?\n\nयह आपके ब्राउज़र में खुलता है; अपने रिकॉर्ड के लिए प्रति रखने हेतु प्रिंट → \"Save as PDF\" का उपयोग करें — ड्राइव बेचते समय या GDPR / डेटा-निपटान प्रमाण के लिए उपयोगी।",
			["MbCloneHelperCreated"] = "वर्तमान कंप्यूटर क्लोन हेल्पर फ़ाइलें बनाई गईं:\n\n{0}\n\nइस Windows के चलते समय पूर्ण क्लोन कैप्चर नहीं किया जा सकता। Windows PE में बूट करें, कैप्चर स्क्रिप्ट चलाएं, फिर DriveForge में 'Restore a full computer clone' चुनें।",
			["Mb029"] = "चुनी गई डिस्क में कोई ड्राइव अक्षर नहीं है। पहले Format का उपयोग करें, फिर क्षमता परीक्षण चलाएं।",
