			["AddAllDriversCheckTip"] = "इस PC के सभी थर्ड-पार्टी ड्राइवर नए Windows में कॉपी करता है (ग्राफिक्स, चिपसेट, ऑडियो, नेटवर्क…)। उसी हार्डवेयर पर इंस्टॉल करते समय सर्वोत्तम। अधिक समय और स्थान लेता है।",
			["HelpTitle"] = "DriveForge कैसे उपयोग करें",
			["HelpBody"] = "DriveForge कैसे उपयोग करें — 3 चरण\r\n\r\n1) चुनें कि क्या बनाना है (ऊपर बाएँ):\r\n   • \"Windows USB बनाएँ\" — डाउनलोड की गई ISO से Windows इंस्टॉल करें।\r\n   • \"इस PC को क्लोन करें\" — मौजूदा Windows को ड्राइव पर कॉपी करें ताकि यह बिल्कुल इस PC की तरह बूट हो।\r\n\r\n2) लक्ष्य ड्राइव चुनें (चरण 3)। उस पर मौजूद सब कुछ मिट जाएगा। रंगीन रेखा बताती है कि ड्राइव उपयुक्त है या नहीं। आपकी सिस्टम डिस्क छिपी है ताकि गलती से न चुनी जाए।\r\n\r\n3) (वैकल्पिक) चरण 4 में विकल्प चुनें — किसी पर माउस ले जाकर विवरण देखें — फिर हरा बटन दबाएँ।\r\n\r\nपूरा होने पर, ड्राइव को लक्ष्य PC में लगाएँ, उसे चालू करें और USB/SSD से शुरू करने के लिए बूट मेनू खोलें (आमतौर पर चालू करते ही F12, F9, Esc या F2)। पहली बार बूट होने में कुछ मिनट लगते हैं।\r\n\r\nउपयोग से पहले ड्राइव की सेहत और गति जाँचने के लिए दाईं ओर के डायग्नोस्टिक सेंटर का उपयोग करें।\r\n\r\n────────────────────────\r\nDriveForge {0}\r\nमुफ़्त • पोर्टेबल (कोई इंस्टॉल नहीं) • सभी सुविधाएँ शामिल — कोई भुगतान वाला स्तर नहीं।\r\nकोई विज्ञापन नहीं। कोई टेलीमेट्री नहीं। कोई खाता नहीं। आपके बारे में कुछ भी एकत्र या कहीं नहीं भेजा जाता।\r\nऑफ़लाइन काम करता है — क्लोन इंजन इसमें पहले से मौजूद है; केवल वैकल्पिक डाउनलोड (ISO या Ventoy इंजन) ही इंटरनेट का उपयोग करते हैं।\r\n\r\nDriveForge मुफ़्त है। इसका समर्थन करने के लिए सेटिंग्स → समर्थन / दान खोलें। धन्यवाद!",
			["HealthToolButtonTip"] = "SMART / विश्वसनीयता स्वास्थ्य को अच्छा / सावधानी / खराब फैसले और तापमान रुझान के साथ पढ़ें।",
			["SpeedToolButtonTip"] = "अनुक्रमिक और रैंडम लेखन गति मापें और ड्राइव को रेट करें।",
			["ScanToolButtonTip"] = "CHKDSK /scan से फ़ाइल सिस्टम की त्रुटियाँ जाँचें (केवल पढ़ने हेतु)।",
			["SurfaceToolButtonTip"] = "खराब / अपठनीय ब्लॉक खोजने के लिए हर सेक्टर पढ़ें (केवल पढ़ने वाला सरफ़ेस टेस्ट)।",
			["CapacityToolButtonTip"] = "ड्राइव की असली क्षमता जाँचें (नकली USB का पता लगाता है)। खाली जगह का परीक्षण करता है।",
			["FormatToolButtonTip"] = "चयनित ड्राइव को क्विक-फ़ॉर्मेट करें (सब कुछ मिटाता है)। NTFS, exFAT या FAT32 चुनें। आपकी सिस्टम डिस्क सुरक्षित है।",
			["PartitionToolButtonTip"] = "पार्टीशन उपकरण: आकार बदलें, हटाएँ-जोड़ें, बनाएँ, हटाएँ, क्विक पार्टीशन, इनिशियलाइज़, MBR/GPT बदलें, जाँचें, सक्रिय करें, खोई हुई खोजें। आपकी सिस्टम डिस्क सुरक्षित है।",
			["TestBootToolButtonTip"] = "PC रीस्टार्ट किए बिना यह जाँचने के लिए कि ड्राइव वाकई बूट होती है, उसे अस्थायी Hyper-V VM में बूट करें। Hyper-V आवश्यक।",
			["WipeToolButtonTip"] = "पूरी ड्राइव (ओवरराइट) या खाली जगह सुरक्षित रूप से मिटाएँ, या SSD TRIM-इरेज़। आपकी सिस्टम डिस्क सुरक्षित है।",
