			["MbDownloadTitle"] = "DriveForge — unduh ISO",
			["MbKitCreated"] = "Kit diagnostik dibuat:\n\n{0}",
			["MbWipeTitle"] = "DriveForge — hapus aman",
			["Mb030"] = "Ruang kosong tidak cukup untuk menguji. Kosongkan atau format drive terlebih dahulu.",
			["MbWipeConfirm"] = "HAPUS SECARA AMAN (erase) drive ini?\n\n    Disk {0} — {1} — {2}\n\nDisk ini saat ini berisi:\n{3}\n\n⚠ Setiap sektor akan DITIMPA. Data TIDAK dapat dipulihkan. Ini tidak dapat dibatalkan.",
			["MbShredConfirm"] = "Hancurkan {0} file secara permanen?\n\nIsi setiap file akan ditimpa ({1} kali) lalu dihapus. Ini tidak dapat dibatalkan.\n\n(Catatan: pada SSD/USB flash, wear-levelling berarti beberapa salinan mungkin masih tersisa secara fisik; untuk kepastian mutlak pada flash, lakukan juga Wipe seluruh drive atau gunakan Secure Erase drive tersebut.)",
			["MbSchedWeekly"] = "setiap hari Minggu",
			["Mb037"] = "Masukkan drive USB yang ingin Anda gunakan, lalu coba lagi.",
			["Mb040"] = "Mulai ulang DriveForge sebagai administrator untuk menjalankan uji permukaan.",
			["Mb034"] = "Tidak dapat menemukan tautan unduhan terkini secara otomatis. Gunakan tombol halaman unduhan resmi sebagai gantinya.",
			["MbFormatDone"] = "Selesai. Disk {0} telah diformat sebagai {1} dan siap digunakan.",
			["Mb031"] = "Itu adalah disk sistem — DriveForge tidak akan menguji boot-nya.",
			["MbBootHelp"] = "\n\nCara menjalankannya: colokkan drive ke PC target, nyalakan, dan buka menu boot (biasanya F12, F9, Esc atau F2 segera setelah dinyalakan), lalu pilih USB/SSD ini. Boot pertama memakan beberapa menit saat Windows menyiapkan driver.",
			["MbBitLockerNote"] = "\n\nCatatan: BitLocker masih mengenkripsi di latar belakang — biarkan drive tetap terhubung sampai mencapai 100% (manage-bde -status), atau enkripsi akan selesai pada boot pertama klon.",
			["MbReinstallConfirm"] = "Pemasangan ulang akan MENGHAPUS semua file (termasuk ISO Anda) pada Disk {0}. Lanjutkan?",
			["Mb028"] = "DriveForge tidak akan menjalankan uji kapasitas pada disk sistem.",
			["Mb042"] = "Pilih drive yang akan diformat terlebih dahulu (Drive to test).",
			["Mb027"] = "Pilih drive yang akan diuji terlebih dahulu (Drive to test).",
			["Mb045"] = "Mulai ulang DriveForge sebagai administrator untuk mengelola partisi.",
			["Mb022"] = "Mulai ulang DriveForge sebagai administrator untuk menghapus drive.",
			["MbMultiBootDone"] = "Selesai! Disk {0} kini menjadi USB multi-boot.\n\nSalin file ISO Anda ke drive \"Ventoy\" yang baru saja terbuka — tambahkan sebanyak yang muat (Windows, Linux, alat penyelamat).\n\nBoot PC mana pun dari drive ini dan pilih ISO dari menu. Tips: gunakan Uji boot untuk memverifikasi bahwa ia boot.",
			["Mb021"] = "Itu adalah disk sistem — DriveForge tidak akan menghapusnya.",
			["MbIsoTooBig"] = "ISO ({0}) lebih besar daripada drive ({1}).",
			["Mb018"] = "Itu adalah disk sistem — tidak dapat dikeluarkan.",
			["Mb015"] = "Belum ada laporan yang tersedia.",
			["Mb016"] = "Drive ini tidak memiliki huruf drive. Format dulu, lalu hapus ruang kosongnya.",
			["Mb013"] = "Kata sandi tidak cocok.",
			["MbNoFreeWipe"] = "Hampir tidak ada ruang kosong untuk dihapus pada {0}:.",
			["MbSchedCreated"] = "Tugas terjadwal \"DriveForge Auto Clone\" dibuat.\n\nTugas ini akan mengklon PC ini ke '{0}' {1} pukul 02:00, selama drive tersebut terhubung.\n\nHapus kapan saja dari Windows Task Scheduler (atau akan diganti jika Anda menjadwalkannya lagi).",
			["MbWipeFreeConfirm"] = "Hapus ruang kosong pada {0}:?\n\nFile Anda yang ada TIDAK disentuh. DriveForge mengisi {1} ruang kosong dengan data penimpaan ({2} kali) lalu menghapusnya, sehingga file yang Anda hapus sebelumnya tidak dapat dipulihkan lagi.\n\nDrive akan penuh untuk sementara selama proses berlangsung. Lanjutkan?",
			["Mb038"] = "Multi-boot didukung oleh engine Ventoy yang gratis dan open-source (GPL-3.0). DriveForge perlu mengunduhnya satu kali (~16 MB); setelah itu disimpan di cache untuk penggunaan offline.\n\nUnduh sekarang?",
			["Mb035"] = "Tempel tautan http(s) langsung ke file ISO.",
			["Mb032"] = "Mulai ulang DriveForge sebagai administrator untuk menjalankan uji boot.",
			["Mb020"] = "Pilih drive yang akan dihapus terlebih dahulu (Drive to test).",
			["MbBootTestOfflineWarn"] = "Uji boot selesai, tetapi menjadikan Disk {0} online kembali mungkin gagal.\n\nJika drive hilang dari Explorer, aktifkan kembali di Disk Management, atau jalankan di PowerShell admin:\n    Set-Disk -Number {0} -IsOffline $false",
			["MbWriteIsoConfirm"] = "Tulis ISO ini ke USB sebagai image bootable?\n\n    ISO: {0} ({1})\n    Ke: Disk {2} — {3} — {4}\n\nDisk ini saat ini berisi:\n{5}\n\n⚠ Semua yang ada di disk akan DIHAPUS. (Berfungsi untuk Linux dan ISO isohybrid lainnya; ISO Windows lebih baik dibuat dengan \"Create Windows USB\".)",
			["Mb041"] = "Tidak ada yang dipilih.",
			["MbHyperV"] = "Uji boot memerlukan fitur Hyper-V, yang tidak diaktifkan pada PC ini.\n\nBuka \"Turn Windows features on or off\" agar Anda dapat mengaktifkan Hyper-V? (Diperlukan mulai ulang setelah mengaktifkannya.)",
			["Mb044"] = "Mulai ulang DriveForge sebagai administrator untuk memformat drive.",
			["MbBootTestConfirm"] = "Uji boot drive ini di mesin virtual?\n\n    Disk {0} — {1} — {2}\n\nDriveForge akan:\n• menjadikan disk ini offline (agar VM dapat menggunakannya),\n• memulai VM {3} sementara yang boot darinya,\n• membuka jendela agar Anda dapat menyaksikannya boot.\n\nCukup perhatikan bahwa ia mencapai menu boot / logo — JANGAN jalankan installer di dalam VM. Setelah selesai, kembali ke sini dan klik OK untuk menghentikan uji dan menjadikan disk online kembali.",
			["Mb019"] = "Drive telah dibersihkan dan dikeluarkan.\n\nJika Windows masih menampilkannya, tunggu sebentar, lalu cabut. (Disk SATA/NVMe internal mungkin tidak dapat dikeluarkan — itu normal.)",
			["MbSurfaceConfirm"] = "Jalankan uji permukaan hanya-baca pada:\n    Disk {0} — {1} — {2}\n\nDriveForge membaca setiap sektor untuk menemukan blok rusak/tidak terbaca. Tidak ada yang ditulis. Drive besar bisa memakan waktu — gunakan Stop untuk membatalkan.",
			["MbVmRunning"] = "VM uji boot sedang berjalan dan jendelanya telah terbuka.\n\n• Jika Anda melihat logo / menu boot drive, drive boot dengan benar. ✓\n• Layar hitam atau \"no bootable device\" berarti drive tidak boot — coba mode firmware lainnya (UEFI ↔ Legacy BIOS).\n\nKlik OK saat selesai untuk menghentikan uji dan menjadikan disk online kembali.",
			["MbMultiBootTitle"] = "DriveForge — USB multi-boot",
			["Mb017"] = "Pilih drive yang akan dilepas terlebih dahulu (langkah 3).",
			["MbShredTitle"] = "DriveForge — hancurkan aman",
			["MbCapacityTitle"] = "DriveForge — uji kapasitas",
			["MbCapacityConfirm"] = "Verifikasi kapasitas SEBENARNYA dari:\n    {0} ({1}:) — mengklaim {2}\n\nIni menulis ~{3} data uji ke ruang KOSONG, membacanya kembali untuk verifikasi, lalu menghapusnya. File Anda yang ada TIDAK disentuh. Untuk pemeriksaan lengkap, jalankan pada drive yang kosong.\n\nLanjutkan?",
			["MbDownloaded"] = "Diunduh:\n    {0}\n\nBuka folder sekarang?",
