			["MbBootHelp"] = "\n\nكيفية بدء التشغيل منه: صِل محرك الأقراص بالكمبيوتر الهدف، وشغّله، وافتح قائمة الإقلاع (عادةً F12 أو F9 أو Esc أو F2 مباشرة بعد التشغيل)، ثم اختر جهاز USB/SSD هذا. يستغرق الإقلاع الأول بضع دقائق بينما يقوم Windows بإعداد برامج التشغيل.",
			["MbBitLockerNote"] = "\n\nملاحظة: لا يزال BitLocker يقوم بالتشفير في الخلفية — أبقِ محرك الأقراص متصلاً حتى يصل إلى 100% (manage-bde -status)، أو سينتهي عند أول إقلاع للنسخة المستنسخة.",
			["MbReinstallConfirm"] = "ستؤدي إعادة التثبيت إلى محو جميع الملفات (بما في ذلك صور ISO الخاصة بك) على القرص {0}. متابعة؟",
			["Mb028"] = "لن يُجري DriveForge اختبار السعة على قرص نظام.",
			["Mb042"] = "حدد محرك الأقراص المراد تهيئته أولاً (محرك الأقراص المراد اختباره).",
			["Mb027"] = "حدد محرك الأقراص المراد اختباره أولاً (محرك الأقراص المراد اختباره).",
			["Mb045"] = "أعد تشغيل DriveForge كمسؤول لإدارة الأقسام.",
			["Mb022"] = "أعد تشغيل DriveForge كمسؤول لمسح محركات الأقراص.",
			["MbMultiBootDone"] = "تم! أصبح القرص {0} الآن USB متعدد الإقلاع.\n\nانسخ ملفات ISO الخاصة بك إلى محرك \"Ventoy\" الذي فُتح للتو — أضف ما يتسع منها (Windows أو Linux أو أدوات الإنقاذ).\n\nأقلِع أي كمبيوتر من محرك الأقراص هذا واختر صورة ISO من القائمة. نصيحة: استخدم اختبار الإقلاع للتحقق من أنه يُقلع.",
			["Mb021"] = "هذا قرص نظام — لن يقوم DriveForge بمسحه.",
			["MbIsoTooBig"] = "صورة ISO ({0}) أكبر من محرك الأقراص ({1}).",
			["Mb018"] = "هذا قرص نظام — لا يمكن إخراجه.",
			["Mb015"] = "لا يتوفر أي تقرير بعد.",
			["Mb016"] = "لا يحتوي محرك الأقراص هذا على حرف محرك أقراص. قم بتهيئته أولاً، ثم امسح مساحته الحرة.",
			["Mb013"] = "كلمتا المرور غير متطابقتين.",
			["MbNoFreeWipe"] = "لا توجد مساحة حرة تقريباً لمسحها على {0}:.",
			["MbSchedCreated"] = "تم إنشاء المهمة المجدولة \"DriveForge Auto Clone\".\n\nستقوم باستنساخ هذا الكمبيوتر إلى '{0}' {1} في الساعة 02:00، طالما أن محرك الأقراص هذا متصل.\n\nأزِلها في أي وقت من Task Scheduler في Windows (أو سيُستبدل إذا قمت بالجدولة مرة أخرى).",
			["MbWipeFreeConfirm"] = "مسح المساحة الحرة على {0}:؟\n\nلن تُمَس ملفاتك الحالية. يملأ DriveForge مساحة {1} الحرة ببيانات الكتابة فوقها ({2} تمريرة) ثم يزيلها، بحيث لم يعد بالإمكان استرداد الملفات التي حذفتها سابقاً.\n\nسيكون محرك الأقراص ممتلئاً مؤقتاً أثناء العملية. متابعة؟",
			["Mb038"] = "يعمل الإقلاع المتعدد بواسطة محرك Ventoy المجاني مفتوح المصدر (GPL-3.0). يحتاج DriveForge إلى تنزيله مرة واحدة (~16 MB)؛ ثم يُخزّن مؤقتاً للاستخدام دون اتصال.\n\nتنزيله الآن؟",
			["Mb035"] = "الصق رابط http(s) مباشراً إلى ملف ISO.",
			["Mb032"] = "أعد تشغيل DriveForge كمسؤول لتشغيل اختبار الإقلاع.",
			["Mb020"] = "حدد محرك الأقراص المراد مسحه أولاً (محرك الأقراص المراد اختباره).",
			["MbBootTestOfflineWarn"] = "انتهى اختبار الإقلاع، لكن إعادة القرص {0} إلى وضع الاتصال ربما فشلت.\n\nإذا كان محرك الأقراص مفقوداً من Explorer، فأعد تفعيله في Disk Management، أو شغّل في PowerShell بصلاحيات المسؤول:\n    Set-Disk -Number {0} -IsOffline $false",
			["MbWriteIsoConfirm"] = "كتابة صورة ISO هذه إلى USB كصورة إقلاعية؟\n\n    ISO: {0} ({1})\n    إلى: القرص {2} — {3} — {4}\n\nيحتوي هذا القرص حالياً على:\n{5}\n\n⚠ سيُمحى كل شيء على القرص. (يعمل مع Linux وصور isohybrid الأخرى؛ من الأفضل إنشاء صورة Windows ISO باستخدام \"Create Windows USB\".)",
			["Mb041"] = "لم يتم تحديد أي شيء.",
			["MbHyperV"] = "يحتاج اختبار الإقلاع إلى ميزة Hyper-V، وهي غير مفعّلة على هذا الكمبيوتر.\n\nفتح \"Turn Windows features on or off\" لتتمكن من تفعيل Hyper-V؟ (يلزم إعادة التشغيل بعد تفعيلها.)",
			["Mb044"] = "أعد تشغيل DriveForge كمسؤول لتهيئة محركات الأقراص.",
			["MbBootTestConfirm"] = "اختبار إقلاع محرك الأقراص هذا في جهاز ظاهري؟\n\n    القرص {0} — {1} — {2}\n\nسيقوم DriveForge بما يلي:\n• نقل هذا القرص إلى وضع عدم الاتصال (حتى يتمكن VM من استخدامه)،\n• بدء تشغيل VM مؤقت بنظام {3} يُقلع منه،\n• فتح نافذة لتتمكن من مشاهدة إقلاعه.\n\nراقب فقط أنه يصل إلى قائمة الإقلاع / الشعار — لا تشغّل أداة تثبيت داخل VM. عند الانتهاء، عُد إلى هنا وانقر OK لإيقاف الاختبار وإعادة القرص إلى وضع الاتصال.",
			["Mb019"] = "تم تفريغ محرك الأقراص وإخراجه.\n\nإذا كان Windows لا يزال يعرضه، فانتظر لحظة ثم افصله. (قد لا تُخرَج أقراص SATA/NVMe الداخلية — وهذا أمر طبيعي.)",
			["MbSurfaceConfirm"] = "تشغيل اختبار سطح للقراءة فقط على:\n    القرص {0} — {1} — {2}\n\nيقرأ DriveForge كل قطاع للعثور على الكتل التالفة/غير القابلة للقراءة. لا تُكتب أي بيانات. قد تستغرق محركات الأقراص الكبيرة بعض الوقت — استخدم Stop للإلغاء.",
			["MbVmRunning"] = "يعمل VM الخاص باختبار الإقلاع وقد فُتحت نافذته.\n\n• إذا رأيت شعار / قائمة إقلاع محرك الأقراص، فهو يُقلع بشكل صحيح. ✓\n• تعني الشاشة السوداء أو \"no bootable device\" أنه لا يُقلع — جرّب وضع البرنامج الثابت الآخر (UEFI ↔ Legacy BIOS).\n\nانقر OK عند الانتهاء لإيقاف الاختبار وإعادة القرص إلى وضع الاتصال.",
			["MbMultiBootTitle"] = "DriveForge — USB متعدد الإقلاع",
			["Mb017"] = "حدد محرك الأقراص المراد إزالته أولاً (الخطوة 3).",
			["MbShredTitle"] = "DriveForge — تمزيق آمن",
			["MbCapacityTitle"] = "DriveForge — اختبار السعة",
			["MbCapacityConfirm"] = "التحقق من السعة الفعلية لـ:\n    {0} ({1}:) — يدّعي {2}\n\nيكتب هذا ~{3} من بيانات الاختبار إلى المساحة الحرة، ويقرأها مرة أخرى للتحقق، ثم يحذفها. لن تُمَس ملفاتك الحالية. للحصول على فحص كامل، شغّله على محرك أقراص فارغ.\n\nمتابعة؟",
			["MbDownloaded"] = "تم التنزيل:\n    {0}\n\nفتح المجلد الآن؟",
			["Mb001"] = "حدد محرك الأقراص الهدف أولاً (الخطوة 3).",
			["Mb002"] = "تعذّر تحديد مسار التطبيق لجدولته.",
			["BzBootVm"] = "جارٍ بدء تشغيل VM لاختبار إقلاع القرص {0}...",
			["MbUsbDone"] = "اكتمل إنشاء USB.",
			["Mb007"] = "حدد جهاز USB/SSD الهدف أولاً.",
			["BzWiping"] = "جارٍ مسح القرص {0} ({1})...",
			["MbSurfaceTitle"] = "DriveForge — اختبار السطح",
			["Mb008"] = "القرص المحدد مُعلَّم كقرص نظام/إقلاع. لن يقوم DriveForge بتهيئته.",
			["Mb026"] = "التحقق من الصورة المكتوبة الآن؟\n\nسيقرأ DriveForge البيانات مرة أخرى من محرك الأقراص ويقارنها بايت بايت مع ISO للتأكد من كتابتها بشكل صحيح (موصى به).",
			["BzCapacity"] = "جارٍ اختبار السعة الفعلية لـ {0}:...",
			["Mb025"] = "يبدو هذا كصورة ISO خاصة بـ Windows / WinPE.\n\nصور Windows ISO ليست \"isohybrid\"، لذا فإن كتابة إحداها كصورة خام عادةً لا تُقلع. للحصول على USB إقلاعي صحيح لـ Windows، استخدم مهمة \"Create Windows USB\" بدلاً من ذلك.\n\nكتابتها كصورة خام على أي حال؟",
			["Mb003"] = "حدد ملف Windows ISO / WIM / ESD أولاً (الخطوة 2).",
			["BzVerify"] = "جارٍ التحقق من القرص {0}...",
			["MbTestBootTitle"] = "DriveForge — اختبار الإقلاع",
			["MbBackupCreated"] = "تم إنشاء صورة النسخة الاحتياطية:\n\n{0}  ({1})\n\nلاستعادتها لاحقاً: اختر \"Advanced: restore full disk image\"، واختر ملف .wim هذا، ثم حدد محرك الأقراص الهدف.",
			["MbFormatConfirm"] = "تهيئة (محو) محرك الأقراص هذا؟\n\n    القرص {0} — {1} — {2}\n\nيحتوي هذا القرص حالياً على:\n{3}\n\n⚠ سيُمحى كل ما سبق نهائياً.",
			["MbSchedDaily"] = "كل يوم",
			["MbBackupNoSpace"] = "لا توجد مساحة حرة كافية في المكان الذي تحفظ فيه الصورة.\n\nالمساحة المقدَّرة المطلوبة: ~{0}\nالمساحة الحرة في الوجهة: {1}",
			["MbWriteIsoTitle"] = "DriveForge — كتابة ISO",
			["Mb014"] = "يجب أن تتكوّن كلمات مرور BitLocker من 8 أحرف على الأقل (أو اترك كلتيهما فارغتين لاستخدام مفتاح الاسترداد فقط).",
			["BzShred"] = "جارٍ تمزيق {0} من الملفات...",
