			["AnRecycleConfirm"] = "إرسال {0} ملف ({1}) إلى سلة المحذوفات؟ يمكنك استعادتها من هناك.",
			["AnPickRow"] = "اختر صفًا أولاً.",
			["EjectWhenDoneCheckTip"] = "عند اكتمال العملية، يُفرغ ذاكرة التخزين ويُخرج محرك الأقراص بأمان لتتمكن من فصله فورًا. يُتخطّى إذا كان BitLocker لا يزال يشفّر.",
			["ScheduleCloneButtonTip"] = "ينشئ مهمة مجدوَلة في Windows تُعيد تشغيل هذا الاستنساخ تلقائيًا (يوميًا أو أسبوعيًا) إلى محرك الأقراص المحدد — نسخة احتياطية تلقائية. أبقِ المحرك موصولًا في ذلك الوقت.",
			["RecoverDeepScanButtonTip"] = "يعثر على الملفات حسب توقيع محتواها (الترويسة/التذييل) عبر كامل محرك الأقراص، حتى عندما لا يحتفظ نظام الملفات بأي سجل لها. الأفضل للصور والمستندات؛ الملفات المستخرجة هكذا لا تحمل اسمها الأصلي.",
			["RecoverMoreButtonTip"] = "المزيد: صورة القرص والجلسات",
			["RecoverZipButtonTip"] = "يستعيد الملفات المحددة مباشرة إلى أرشيف .zip واحد.",
			["DonateButtonTip"] = "يفتح صفحة Ko-fi الخاصة بـ DriveForge في متصفحك (الدفع بالبطاقة أو Apple/Google Pay أو PayPal — دون حساب). لا يطلب التطبيق نفسه تفاصيل الدفع أو يتعامل معها أبدًا.",
			["BitLockerCheckTip"] = "يشفّر محرك الأقراص الجديد لحماية البيانات في حال فقده أو سرقته. تختار كلمة مرور؛ ويُحفظ مفتاح استرداد أيضًا في ملف تختاره.",
			["BitLockerResumeCheckTip"] = "قد يستغرق التشفير بعض الوقت. مع تفعيل هذا يمكنك الفصل بمجرد انتهاء الاستنساخ — يُكمل Windows التشفير تلقائيًا عند أول إقلاع للنسخة.",
			["DataPartitionCheckTip"] = "يحدّ Windows بحجم معقول ويحوّل المساحة الحرة المتبقية إلى محرك ثانٍ فارغ (مثلًا لملفاتك).",
			["CloneOtherPartitionsCheckTip"] = "إذا كان قرص هذا الكمبيوتر يحتوي أقسام بيانات أخرى (مثل محرك D:)، انسخها أيضًا إلى الهدف، كلٌّ في قسمه الخاص.",
			["VerifyContentCheckTip"] = "بعد الاستنساخ، يعيد قراءة كل ملف من محرك الأقراص ويقارنه بالأصل لاكتشاف وحدة USB معيبة. يضيف وقتًا؛ ألغِ التحديد فقط إذا كنت تثق بالمحرك.",
			["CompactImageCheckTip"] = "يخزّن Windows مضغوطًا ليأخذ مساحة أقل على محرك الأقراص. يوفّر المساحة؛ تُفتح التطبيقات أبطأ قليلًا. مناسب لمحركات USB الأصغر.",
			["VerifyIsoButtonTip"] = "يحسب SHA-256 لملف ISO المحدد لتقارنه بالقيمة الموجودة في صفحة التنزيل الرسمية — يؤكد أن الملف أصلي وغير تالف.",
			["BypassRequirementsCheckTip"] = "يتيح تثبيت Windows 11 على أجهزة بلا TPM 2.0 / التمهيد الآمن / معالج جديد. يهمّ فقط عند التثبيت الجديد من ISO — فعّله إذا كان جهازك \"غير مدعوم\".",
			["BypassAccountCheckTip"] = "يتخطى اشتراط حساب Microsoft عند أول إقلاع. سيُطلب منك اختيار اسم حساب محلي وكلمة مرور أثناء الإنشاء.",
			["DebloatCheckTip"] = "يكتب إعدادات نهج المجموعة الخاصة بـ Microsoft في النظام الجديد لإيقاف Copilot وأيقونة Teams/Chat والتطبيقات والإعلانات المقترحة والبحث على الويب في قائمة ابدأ ومعرّف الإعلانات، ولضبط القياس عن بُعد إلى الحد الأدنى. يُطبَّق دون اتصال على صورة التثبيت — قابل للعكس ولا يثبّت أي شيء إضافي.",
			["AddNetworkDriversCheckTip"] = "ينسخ برامج تشغيل الشبكة وWi-Fi لهذا الكمبيوتر إلى النظام الجديد ليظهر Wi-Fi أثناء الإعداد الأول. الأكثر فائدة عند التثبيت على الجهاز نفسه أو جهاز مشابه.",
			["AddAllDriversCheckTip"] = "ينسخ كل برامج التشغيل من الجهات الخارجية من هذا الكمبيوتر إلى النظام الجديد (الرسوميات، مجموعة الشرائح، الصوت، الشبكة…). الأفضل عند التثبيت على العتاد نفسه. يستغرق وقتًا أطول ومساحة أكبر.",
			["HelpTitle"] = "كيفية استخدام DriveForge",
			["HelpBody"] = "كيفية استخدام DriveForge — 3 خطوات\r\n\r\n1) اختر ما تريد إنشاءه (أعلى اليسار):\r\n   • \"إنشاء USB ويندوز\" — تثبيت ويندوز من ملف ISO قمت بتنزيله.\r\n   • \"استنساخ هذا الكمبيوتر\" — نسخ ويندوز الحالي إلى محرك الأقراص ليُقلع تمامًا مثل هذا الكمبيوتر.\r\n\r\n2) اختر محرك الأقراص الهدف (الخطوة 3). سيُمحى كل ما عليه. يوضح الخط الملوّن ما إذا كان المحرك مناسبًا. قرص النظام مخفي حتى لا تختاره عن طريق الخطأ.\r\n\r\n3) (اختياري) فعّل الخيارات في الخطوة 4 — مرّر المؤشر فوق أي خيار للحصول على شرح — ثم اضغط الزر الأخضر.\r\n\r\nعند الانتهاء، وصّل المحرك بالكمبيوتر الهدف، شغّله وافتح قائمة الإقلاع (عادةً F12 أو F9 أو Esc أو F2 فور التشغيل) للإقلاع من USB/SSD. يستغرق الإقلاع الأول بضع دقائق.\r\n\r\nاستخدم مركز التشخيص على اليمين للتحقق من صحة وسرعة محرك الأقراص قبل استخدامه.\r\n\r\n────────────────────────\r\nDriveForge {0}\r\nمجاني • محمول (بلا تثبيت) • جميع الميزات مضمّنة — بلا مستويات مدفوعة.\r\nبلا إعلانات. بلا قياس عن بُعد. بلا حسابات. لا يُجمع أي شيء عنك ولا يُرسل إلى أي مكان.\r\nيعمل دون اتصال بالإنترنت — محرك الاستنساخ مدمج في التطبيق؛ والتنزيلات الاختيارية فقط (ملفات ISO أو محرك Ventoy) هي التي تستخدم الإنترنت.\r\n\r\nDriveForge مجاني. لدعمه، افتح الإعدادات → الدعم / التبرّع. شكرًا لك!",
			["HealthToolButtonTip"] = "يقرأ حالة SMART / الموثوقية مع حكم جيد / تحذير / سيئ واتجاه درجة الحرارة.",
			["SpeedToolButtonTip"] = "يقيس سرعة الكتابة التسلسلية والعشوائية ويقيّم محرك الأقراص.",
			["ScanToolButtonTip"] = "يفحص نظام الملفات بحثًا عن الأخطاء باستخدام CHKDSK /scan (للقراءة فقط).",
			["SurfaceToolButtonTip"] = "يقرأ كل قطاع للعثور على الكتل التالفة / غير المقروءة (اختبار سطحي للقراءة فقط).",
			["CapacityToolButtonTip"] = "يتحقق من السعة الحقيقية لمحرك الأقراص (يكشف وحدات USB المزيّفة). يختبر المساحة الحرة.",
			["FormatToolButtonTip"] = "تهيئة سريعة لمحرك الأقراص المحدد (يمحو كل شيء). اختر NTFS أو exFAT أو FAT32. قرص النظام محمي.",
